// 中医经典古籍数据库
// 包含倪海厦四件套等中医经典

export interface Clause {
  id: string
  chapter: string
  original: string
  translation: string
  annotation: string
}

export interface HerbEntry {
  id: string
  name: string
  alias?: string
  nature: string
  flavor: string
  meridians: string
  original: string
  translation: string
  effects: string
  usage?: string
}

export interface ClassicBook {
  id: string
  name: string
  author: string
  dynasty: string
  description: string
  content: string[]
  coreTheory: string[]
  famousFormulas: string[]
  keyConcepts: string[]
  hasFullText: boolean
  clauses?: Clause[]
  herbs?: HerbEntry[]
}

// ============ 伤寒论 ============

const SHANGHAN_LUN_CLAUSES: Clause[] = [
  { id: "SH-001", chapter: "辨太阳病脉证并治上", original: "太阳之为病，脉浮，头项强痛而恶寒。", translation: "太阳病的典型表现是：脉象浮，头部和项部僵硬疼痛，并且怕冷。", annotation: "此为太阳病提纲。脉浮主表，头项强痛为太阳经脉受邪，恶寒为风寒外束卫阳被遏。凡见此脉证，即可诊断为太阳病。" },
  { id: "SH-002", chapter: "辨太阳病脉证并治上", original: "太阳病，发热，汗出，恶风，脉缓者，名为中风。", translation: "太阳病的症状中，如果有发热、出汗、怕风、脉象浮缓，就叫做中风证。", annotation: "中风为太阳表虚证。风邪疏泄，卫气不固，故汗出恶风。桂枝汤主之。与麻黄汤证的无汗恶寒相鉴别。" },
  { id: "SH-003", chapter: "辨太阳病脉证并治上", original: "太阳病，或已发热，或未发热，必恶寒，体痛，呕逆，脉阴阳俱紧者，名为伤寒。", translation: "太阳病，有的已经发热，有的还未发热，但必定怕冷，身体疼痛，呕吐气逆，寸关尺三部脉象都紧，这叫做伤寒。", annotation: "伤寒为太阳表实证。寒邪束表，卫阳被遏，营阴郁滞。无汗、恶寒、身痛、脉紧为辨证要点。麻黄汤主之。" },
  { id: "SH-004", chapter: "辨太阳病脉证并治上", original: "伤寒一日，太阳受之，脉若静者，为不传；颇欲吐，若躁烦，脉数急者，为传也。", translation: "伤寒第一天，太阳经受邪，如果脉象平静没有变化，说明病邪没有传变；如果很想呕吐，或者烦躁不安，脉象数急，说明病邪已经传变。", annotation: "本条论述伤寒传变与否的辨证要点。脉静为不传，欲吐、躁烦、脉数急为传变之象。临证需动态观察脉证变化。" },
  { id: "SH-005", chapter: "辨太阳病脉证并治上", original: "伤寒二三日，阳明少阳证不见者，为不传也。", translation: "伤寒二三天后，如果没有见到阳明病或少阳病的症状，说明病邪没有传变，仍在太阳。", annotation: "阳明证见不恶寒反恶热、口渴、便秘等；少阳证见往来寒热、胸胁苦满、默默不欲饮食等。二经证不见则不传。" },
  { id: "SH-006", chapter: "辨太阳病脉证并治上", original: "太阳病，发热而渴，不恶寒者，为温病。若发汗已，身灼热者，名风温。", translation: "太阳病，发热并且口渴，不怕冷的，是温病。如果发汗以后，身体发热得像烧灼一样，叫做风温。", annotation: "此条论述温病与伤寒的鉴别。温病发热而渴不恶寒，为内热已盛。误用辛温发汗则邪热更炽，身灼热而转为风温。" },
  { id: "SH-007", chapter: "辨太阳病脉证并治上", original: "病有发热恶寒者，发于阳也；无热恶寒者，发于阴也。发于阳，七日愈；发于阴，六日愈。", translation: "病有发热而又怕冷的，是发于阳经；没有发热而只怕冷的，是发于阴经。发于阳经的七天可以痊愈；发于阴经的六天可以痊愈。", annotation: "此为辨病发阴阳的总纲。发热恶寒为阳证（三阳），正气尚能抗邪；无热恶寒为阴证（三阴），阳气虚衰无力抗邪。" },
  { id: "SH-008", chapter: "辨太阳病脉证并治上", original: "太阳病，头痛至七日以上自愈者，以行其经尽故也。若欲作再经者，针足阳明，使经不传则愈。", translation: "太阳病，头痛到七天以上自己痊愈的，是因为邪气在本经中运行完毕。如果想要防止传经，可以针刺足阳明经的穴位，使邪气不传经就会痊愈。", annotation: "七日为太阳经气一周之期。经尽邪衰则自愈。预防传经可针足阳明足三里等穴，增强正气。" },
  { id: "SH-009", chapter: "辨太阳病脉证并治上", original: "太阳病，欲解时，从巳至未上。", translation: "太阳病想要解除的时间，从巳时到未时（上午9点到下午3点左右）。", annotation: "六经病欲解时皆与经气旺盛之时相应。太阳为三阳，巳至未为阳中之阳，太阳经气旺盛之时，正盛则邪退。" },
  { id: "SH-010", chapter: "辨太阳病脉证并治上", original: "风家，表解而不了了者，十二日愈。", translation: "平素容易感受风邪的人，表邪已经解除但身体还没有完全恢复清爽，十二天可以痊愈。", annotation: "风家指常患感冒之人。表证虽解，但正气未复，需十二日经气两周方能完全康复。不宜再用药攻邪。" },
  { id: "SH-011", chapter: "辨太阳病脉证并治上", original: "病人身大热，反欲得衣者，热在皮肤，寒在骨髓也；身大寒，反不欲近衣者，寒在皮肤，热在骨髓也。", translation: "病人身体表面很热，反而想要多穿衣服的，是热在皮肤（假热），寒在骨髓（真寒）；身体表面很冷，反而不想靠近衣服的，是寒在皮肤（假寒），热在骨髓（真热）。", annotation: "此条辨别寒热真假的关键。真寒假热（阴盛格阳）：身热欲衣，脉必沉微；真热假寒（阳盛格阴）：身寒不欲衣，脉必滑数。" },
  { id: "SH-012", chapter: "辨太阳病脉证并治上", original: "太阳中风，阳浮而阴弱，阳浮者，热自发，阴弱者，汗自出，啬啬恶寒，淅淅恶风，翕翕发热，鼻鸣干呕者，桂枝汤主之。", translation: "太阳中风证，脉象浮取有余而沉取不足，卫阳浮于外所以自然发热，营阴不足所以汗自出，怕冷得瑟瑟发抖，怕风得淅淅发冷，发热如翕合之状，鼻中鸣响而干呕的，用桂枝汤主治。", annotation: "此桂枝汤证典型表现。阳浮阴弱即浮缓之脉。啬啬、淅淅、翕翕都是形容恶寒发热之状。桂枝汤调和营卫，为群方之冠。" },
  { id: "SH-013", chapter: "辨太阳病脉证并治上", original: "太阳病，头痛发热，汗出恶风，桂枝汤主之。", translation: "太阳病，头痛发热，出汗怕风，用桂枝汤主治。", annotation: "桂枝汤证四大症：头痛、发热、汗出、恶风。抓住这几个主症即可用桂枝汤，不必诸症悉具。" },
  { id: "SH-014", chapter: "辨太阳病脉证并治上", original: "太阳病，项背强几几，反汗出恶风者，桂枝加葛根汤主之。", translation: "太阳病，项背部僵硬不适，反而出汗怕风的，用桂枝加葛根汤主治。", annotation: "项背强几几为经气不舒。无汗为葛根汤证（麻黄汤+葛根），有汗为桂枝加葛根汤证。葛根升津液、舒经脉。" },
  { id: "SH-015", chapter: "辨太阳病脉证并治上", original: "太阳病，下之后，其气上冲者，可与桂枝汤，方用前法；若不上冲者，不得与之。", translation: "太阳病，误用下法之后，如果病人自觉有气上冲的，说明表证仍在，可以给予桂枝汤，按照以前的方法服用；如果没有气上冲的感觉，就不能再用桂枝汤了。", annotation: "气上冲是正气抗邪、邪仍在表之征。下后正伤而气不上冲，说明邪已内陷，不可再用桂枝汤解表。" },
  { id: "SH-016", chapter: "辨太阳病脉证并治上", original: "太阳病三日，已发汗，若吐、若下、若温针，仍不解者，此为坏病，桂枝不中与之也。观其脉证，知犯何逆，随证治之。", translation: "太阳病三天，已经发过汗，或者用了吐法、下法、温针，病仍然不解的，这就成了坏病，不能再用桂枝汤了。观察其脉象和症状，了解犯了什么错误，随证治疗。", annotation: "坏病即变证，因误治所致。'观其脉证，知犯何逆，随证治之'为张仲景辨证论治的核心思想。" },
  { id: "SH-017", chapter: "辨太阳病脉证并治上", original: "桂枝本为解肌，若其人脉浮紧，发热汗不出者，不可与之也。常须识此，勿令误也。", translation: "桂枝汤本来是用来调和营卫、解除肌表之邪的，如果病人脉象浮紧，发热不出汗的，不可用桂枝汤。常常记住这一点，不要误用。", annotation: "此为桂枝汤禁忌。脉浮紧、无汗为伤寒表实，当用麻黄汤。误用桂枝汤会使表邪更加闭郁不出。" },
  { id: "SH-018", chapter: "辨太阳病脉证并治上", original: "若酒客病，不可与桂枝汤，得之则呕，以酒客不喜甘故也。", translation: "如果平素嗜酒的人患病，不可给予桂枝汤，服了就会呕吐，因为嗜酒的人不喜欢甘味的缘故。", annotation: "酒客多湿热内蕴，桂枝汤甘温，服之助湿增热，胃气上逆则呕。可改用辛凉解表或清热化湿之法。" },
  { id: "SH-019", chapter: "辨太阳病脉证并治上", original: "喘家，作桂枝汤，加厚朴杏子佳。", translation: "素有喘病的人得了桂枝汤证，服用桂枝汤时加上厚朴、杏仁效果更好。", annotation: "厚朴降气平喘，杏仁宣肺止咳。此为桂枝加厚朴杏子汤，适用于太阳中风兼素有喘疾或误下后微喘者。" },
  { id: "SH-020", chapter: "辨太阳病脉证并治上", original: "凡服桂枝汤吐者，其后必吐脓血也。", translation: "凡是服用桂枝汤后呕吐的，其后必定会吐脓血。", annotation: "服桂枝汤而吐，说明内有湿热或痈脓。桂枝汤辛温助热，热毒上迫则吐脓血。此为内热已盛之征兆。" },
  { id: "SH-021", chapter: "辨太阳病脉证并治中", original: "太阳病，发汗，遂漏不止，其人恶风，小便难，四肢微急，难以屈伸者，桂枝加附子汤主之。", translation: "太阳病，发汗太过，导致汗出不止，病人怕风，小便困难，四肢轻微拘急，难以屈伸的，用桂枝加附子汤主治。", annotation: "汗多亡阳，卫外不固则恶风漏汗；津液外泄则小便难；筋脉失养则四肢拘急。桂枝汤调和营卫，加附子回阳固表。" },
  { id: "SH-022", chapter: "辨太阳病脉证并治中", original: "太阳病，下之后，脉促胸满者，桂枝去芍药汤主之。", translation: "太阳病，误用下法后，脉象急促而胸部胀满的，用桂枝去芍药汤主治。", annotation: "误下伤阳，胸阳不振。芍药酸寒益阴，有碍胸阳宣通，故去之。桂枝去芍药汤温通胸阳。" },
  { id: "SH-023", chapter: "辨太阳病脉证并治中", original: "若微寒者，桂枝去芍药加附子汤主之。", translation: "如果病人有轻微怕冷的，用桂枝去芍药加附子汤主治。", annotation: "微寒为阳虚较甚，不仅胸阳不振，且卫阳亦虚。加附子温经扶阳。" },
  { id: "SH-024", chapter: "辨太阳病脉证并治中", original: "太阳病，得之八九日，如疟状，发热恶寒，热多寒少，其人不呕，清便欲自可，一日二三度发。脉微缓者，为欲愈也；脉微而恶寒者，此阴阳俱虚，不可更发汗、更下、更吐也。", translation: "太阳病，已经八九天了，症状像疟疾一样，发热恶寒，发热多而恶寒少，病人不呕吐，大小便基本正常，一天发作两三次。脉象微而缓和的，是将要痊愈；脉象微弱而怕冷的，这是阴阳都虚，不能再发汗、再攻下、再涌吐了。", annotation: "如疟状为正邪交争。热多寒少、不呕、清便自可为邪渐衰正渐复。脉微缓为欲愈；脉微恶寒为阴阳两虚，当温阳益阴。" },
  { id: "SH-025", chapter: "辨太阳病脉证并治中", original: "面色反有热色者，未欲解也，以其不能得小汗出，身必痒，宜桂枝麻黄各半汤。", translation: "面色反而出现红色的，说明病还未解除，因为不能得到轻微出汗，身体必定发痒，适宜用桂枝麻黄各半汤。", annotation: "面色红为佛郁在表不得小汗。身痒为邪在皮肤欲出不得。桂麻各半汤小发其汗，调和营卫兼解表。" },
  { id: "SH-026", chapter: "辨太阳病脉证并治中", original: "服桂枝汤，大汗出，脉洪大者，与桂枝汤如前法。若形似疟，一日再发者，汗出必解，宜桂枝二麻黄一汤。", translation: "服用桂枝汤后，大汗出，脉象洪大的，仍然给予桂枝汤按照以前的方法服用。如果症状像疟疾，一天发作两次的，出汗后必定解除，适宜用桂枝二麻黄一汤。", annotation: "大汗出而脉洪大，若烦渴不解则为转阳明白虎汤证；若无烦渴则表证仍在。形似疟一日再发为表邪较轻，桂二麻一汤微发其汗。" },
  { id: "SH-027", chapter: "辨太阳病脉证并治中", original: "太阳病，发热恶寒，热多寒少，脉微弱者，此无阳也，不可发汗，宜桂枝二越婢一汤。", translation: "太阳病，发热恶寒，发热多而恶寒少，脉象微弱的，这是阳气虚弱，不可发汗，适宜用桂枝二越婢一汤。", annotation: "热多寒少为表有邪而内有热，脉微弱为阳不足。桂枝二越婢一汤小发其汗兼清内热，为表里双解轻剂。" },
  { id: "SH-028", chapter: "辨太阳病脉证并治中", original: "服桂枝汤，或下之，仍头项强痛，翕翕发热，无汗，心下满微痛，小便不利者，桂枝去桂加茯苓白术汤主之。", translation: "服用桂枝汤，或者用了下法，仍然头项僵硬疼痛，翕翕发热，无汗，胃脘部胀满微痛，小便不通利的，用桂枝去桂加茯苓白术汤主治。", annotation: "此为水气内停、太阳经气不舒。去桂枝之辛散，加茯苓白术健脾利水。水去则表里自和。" },
  { id: "SH-029", chapter: "辨太阳病脉证并治中", original: "伤寒，脉浮，自汗出，小便数，心烦，微恶寒，脚挛急，反与桂枝欲攻其表，此误也。得之便厥，咽中干，烦躁吐逆者，作甘草干姜汤与之，以复其阳。", translation: "伤寒，脉象浮，自汗出，小便次数多，心烦，微恶寒，脚拘挛紧急，反而给予桂枝汤想要攻散表邪，这是错误的。服药后就会出现四肢厥冷，咽喉干燥，烦躁呕吐气逆的，制作甘草干姜汤给予，以恢复其阳气。", annotation: "此为阴阳两虚证。自汗、小便数为阳虚不固；心烦、脚挛急为阴液不足。误用桂枝汤发表更伤阳。先与甘草干姜汤回阳，后再养阳。" },
  { id: "SH-030", chapter: "辨太阳病脉证并治中", original: "若厥愈足温者，更作芍药甘草汤与之，其脚即伸。若胃气不和谵语者，少与调胃承气汤。若重发汗，复加烧针者，四逆汤主之。", translation: "如果厥冷痊愈足部转温的，再制作芍药甘草汤给予，他的脚就能伸展了。如果胃气不和而说胡话的，少量给予调胃承气汤。如果又发汗，又加用烧针的，用四逆汤主治。", annotation: "此条示人随证治之之法。阳回复厥愈足温后，用芍药甘草汤酸甘化阴、缓急舒筋。胃气不和用调胃承气汤。亡阳重证用四逆汤。" },
  { id: "SH-031", chapter: "辨太阳病脉证并治中", original: "问曰：证象阳旦，按法治之而增剧，厥逆，咽中干，两胫拘急而谵语。师曰：言夜半手足当温，两脚当伸，后如师言。何以知此？答曰：寸口脉浮而大，浮为风，大为虚，风则生微热，虚则两胫挛。病证象桂枝，因加附子参其间，增桂令汗出，附子温经，亡阳故也。厥逆咽中干，烦躁，阳明内结，谵语烦乱，更饮甘草干姜汤，夜半阳气还，两足当热，胫尚微拘急，重与芍药甘草汤，尔乃胫伸。以承气汤微溏，则止其谵语，故知病可愈。", translation: "问道：症状像阳旦证（桂枝汤证），按照方法治疗反而加重，出现四肢厥逆，咽喉干燥，两小腿拘急而说胡话。老师说：到了半夜手足应当转温，两脚应当伸展，后来正如老师说的那样。怎么知道会这样呢？回答说：寸口脉浮而大，浮是风邪，大是正虚，有风邪就会生微热，正虚就会两小腿拘挛。病证像桂枝汤证，因为加了附子在里面，增加桂枝用量使汗出，附子温经，这是亡阳的缘故。厥逆咽中干，烦躁，阳明内结，谵语烦乱，再饮用甘草干姜汤，半夜阳气恢复，两足应当发热，小腿还微拘急，再给芍药甘草汤，于是小腿伸展。用承气汤使大便微溏，就止住了谵语，所以知道病可以痊愈。", annotation: "此条为上条的详细解释，示范了辨证论治的全过程。寸口脉浮大为风虚相搏，误加附子增桂枝汗出更亡阳。先回阳后养阳，再调胃，次第分明。" },
  { id: "SH-032", chapter: "辨太阳病脉证并治中", original: "太阳病，项背强几几，无汗，恶风，葛根汤主之。", translation: "太阳病，项背部僵硬不适，无汗，怕风的，用葛根汤主治。", annotation: "无汗恶风为伤寒表实，项背强几几为经气不舒。葛根汤（葛根、麻黄、桂枝、芍药、甘草、生姜、大枣）发汗解表、升津液舒经脉。" },
  { id: "SH-033", chapter: "辨太阳病脉证并治中", original: "太阳与阳明合病者，必自下利，葛根汤主之。", translation: "太阳与阳明同时发病的，必定会自行下利，用葛根汤主治。", annotation: "二阳合病，表邪内迫阳明而下利。葛根汤解表为主，表解则里自和。葛根亦能升清止利。" },
  { id: "SH-034", chapter: "辨太阳病脉证并治中", original: "太阳与阳明合病，不下利，但呕者，葛根加半夏汤主之。", translation: "太阳与阳明同时发病，不下利，只呕吐的，用葛根加半夏汤主治。", annotation: "不下利但呕为胃气上逆。葛根汤解表，加半夏降逆止呕。" },
  { id: "SH-035", chapter: "辨太阳病脉证并治中", original: "太阳病，桂枝证，医反下之，利遂不止，脉促者，表未解也；喘而汗出者，葛根黄芩黄连汤主之。", translation: "太阳病，桂枝汤证，医生反而用下法，导致泄泻不止，脉象急促的，是表邪还未解除；气喘而出汗的，用葛根黄芩黄连汤主治。", annotation: "误下邪陷阳明，表证未解而里热已盛。脉促为表未解。喘而汗出为里热熏蒸。葛根芩连汤表里双解，清热止利。" },
  { id: "SH-036", chapter: "辨太阳病脉证并治中", original: "太阳病，头痛发热，身疼腰痛，骨节疼痛，恶风，无汗而喘者，麻黄汤主之。", translation: "太阳病，头痛发热，身体疼痛腰痛，骨节疼痛，怕风，无汗而气喘的，用麻黄汤主治。", annotation: "麻黄汤证八大症：头痛、发热、身疼、腰痛、骨节疼痛、恶风、无汗、喘。脉必浮紧。为太阳伤寒表实证之主方。" },
  { id: "SH-037", chapter: "辨太阳病脉证并治中", original: "太阳与阳明合病，喘而胸满者，不可下，宜麻黄汤。", translation: "太阳与阳明同时发病，气喘而胸部胀满的，不可攻下，适宜用麻黄汤。", annotation: "喘而胸满为表邪郁肺，肺气不宣。虽有阳明证但以表证为主，当先解表用麻黄汤，不可攻下。" },
  { id: "SH-038", chapter: "辨太阳病脉证并治中", original: "太阳病，十日以去，脉浮细而嗜卧者，外已解也。设胸满胁痛者，与小柴胡汤；脉但浮者，与麻黄汤。", translation: "太阳病，十天以后，脉象浮细而喜欢躺卧的，是表邪已经解除了。如果有胸部胀满胁痛的，给予小柴胡汤；脉象只是浮的，给予麻黄汤。", annotation: "十日以上当观其变。脉浮细嗜卧为邪去正衰。胸满胁痛为邪入少阳。脉但浮为邪仍在表。" },
  { id: "SH-039", chapter: "辨太阳病脉证并治中", original: "太阳中风，脉浮紧，发热恶寒，身疼痛，不汗出而烦躁者，大青龙汤主之。若脉微弱，汗出恶风者，不可服之。服之则厥逆，筋惕肉瞤，此为逆也。", translation: "太阳中风，脉象浮紧，发热恶寒，身体疼痛，不出汗而烦躁的，用大青龙汤主治。如果脉象微弱，汗出怕风的，不可服用。服了就会四肢厥逆，筋惕肉瞤，这是治疗错误。", annotation: "大青龙汤为麻黄汤倍麻黄加石膏生姜大枣，发汗解表兼清内热。不汗出而烦躁为表寒里热之征。脉微弱汗出为阳虚，误服则亡阳。" },
  { id: "SH-040", chapter: "辨太阳病脉证并治中", original: "伤寒，脉浮缓，身不疼，但重，乍有轻时，无少阴证者，大青龙汤发之。", translation: "伤寒，脉象浮缓，身体不疼痛，只是沉重，忽然有减轻的时候，没有少阴病症状的，用大青龙汤发汗。", annotation: "身重乍轻为湿困或表闭阳郁。无少阴证（脉微细、但欲寐、厥冷等）方可发汗。大青龙汤散表寒清内热。" },
  { id: "SH-041", chapter: "辨太阳病脉证并治中", original: "伤寒，表不解，心下有水气，干呕发热而咳，或渴，或利，或噎，或小便不利、少腹满，或喘者，小青龙汤主之。", translation: "伤寒，表邪未解除，胃脘部有水气，干呕发热而咳嗽，或者口渴，或者下利，或者噎塞，或者小便不通利、少腹胀满，或者气喘的，用小青龙汤主治。", annotation: "小青龙汤解表化饮。表不解兼心下有水气为辨证要点。干呕、咳、喘、小便不利为水饮内停之证。麻黄桂枝解表，干姜细辛半夏化饮，五味芍药敛肺。" },
  { id: "SH-042", chapter: "辨太阳病脉证并治中", original: "伤寒，心下有水气，咳而微喘，发热不渴。服汤已渴者，此寒去欲解也，小青龙汤主之。", translation: "伤寒，胃脘部有水气，咳嗽而微喘，发热不口渴。服药后口渴的，这是寒饮已去病将解除，用小青龙汤主治。", annotation: "不渴为水饮内停。服药后渴为寒饮已去，阳气恢复，津液一时未复。此为向愈之兆。" },
  { id: "SH-043", chapter: "辨太阳病脉证并治中", original: "太阳病，外证未解，脉浮弱者，当以汗解，宜桂枝汤。", translation: "太阳病，表证未解除，脉象浮弱的，应当用发汗的方法解除，适宜用桂枝汤。", annotation: "脉浮弱为表虚，宜桂枝汤调和营卫，不可用麻黄汤峻汗。" },
  { id: "SH-044", chapter: "辨太阳病脉证并治中", original: "太阳病，下之微喘者，表未解故也，桂枝加厚朴杏子汤主之。", translation: "太阳病，用下法后出现轻微气喘的，是表邪还未解除的缘故，用桂枝加厚朴杏子汤主治。", annotation: "误下后表未解而肺气上逆。桂枝汤解表，厚朴杏子降气平喘。" },
  { id: "SH-045", chapter: "辨太阳病脉证并治中", original: "太阳病，外证未解，不可下也，下之为逆。欲解外者，宜桂枝汤。", translation: "太阳病，表证未解除，不可攻下，攻下就是错误。想要解除表邪的，适宜用桂枝汤。", annotation: "此条重申先表后里的治疗原则。外证未解当先解表，若先下之为逆。" },
  { id: "SH-046", chapter: "辨太阳病脉证并治中", original: "太阳病，先发汗不解，而复下之，脉浮者不愈。浮为在外，而反下之，故令不愈。今脉浮，故在外，当须解外则愈，宜桂枝汤。", translation: "太阳病，先发汗病不解，又用下法，脉象浮的不会痊愈。浮是邪在表，反而攻下，所以使病不愈。现在脉象浮，所以邪在表，应当解除表邪就会痊愈，适宜用桂枝汤。", annotation: "脉浮为邪仍在表，虽经误下仍当解表。先汗后下为正治，若汗不解而径下为误。" },
  { id: "SH-047", chapter: "辨太阳病脉证并治中", original: "太阳病，脉浮紧，无汗，发热，身疼痛，八九日不解，表证仍在，此当发其汗。服药已微除，其人发烦目瞑，剧者必衄，衄乃解。所以然者，阳气重故也。麻黄汤主之。", translation: "太阳病，脉象浮紧，无汗，发热，身体疼痛，八九天不解，表证仍在，这应当发汗。服药后症状稍减，病人心中发烦眼睛昏蒙，严重的必定鼻出血，鼻出血后病就解除了。之所以这样，是因为阳气郁闭太重的缘故。用麻黄汤主治。", annotation: "八九日表证仍在，说明邪仍在表。服药后发烦目瞑为邪正交争。衄乃解为红汗，邪从衄解。阳气重指表寒郁闭太甚。" },
  { id: "SH-048", chapter: "辨太阳病脉证并治中", original: "太阳病，脉浮紧，发热，身无汗，自衄者愈。", translation: "太阳病，脉象浮紧，发热，身体无汗，自行鼻出血的就会痊愈。", annotation: "自衄为正气抗邪，邪热随衄而泄。衄血作汗解，病自愈。" },
  { id: "SH-049", chapter: "辨太阳病脉证并治中", original: "二阳并病，太阳初得病时，发其汗，汗先出不彻，因转属阳明，续自微汗出，不恶寒。若太阳病证不罢者，不可下，下之为逆，如此可小发汗。", translation: "太阳与阳明二阳并病，太阳初得病时，发其汗，汗出不透彻，因而转属阳明，接着自行微微出汗，不恶寒。如果太阳病证还未罢的，不可攻下，攻下就是错误，像这样可以轻微发汗。", annotation: "汗出不彻则邪不外达而内传阳明。续自汗出不恶寒为阳明证。但太阳证不罢者，当先解表后攻里，不可先下。" },
  { id: "SH-050", chapter: "辨太阳病脉证并治中", original: "设面色缘缘正赤者，阳气怫郁在表，当解之、熏之。若发汗不彻，不足言，阳气怫郁不得越，当汗不汗，其人躁烦，不知痛处，乍在腹中，乍在四肢，按之不可得，其人短气，但坐以汗出不彻故也，更发汗则愈。何以知汗出不彻？以脉涩故知也。", translation: "如果面色持续发红的，是阳气郁滞在表，应当发汗解表、熏蒸取汗。如果发汗不透彻，不用说，阳气郁滞不得发越，应当发汗而不发汗，病人烦躁，不知疼痛在哪里，忽在腹中，忽在四肢，按摸不到疼痛所在，病人气短，只是因为汗出不透彻的缘故，再发汗就会痊愈。怎么知道汗出不透彻？因为脉象涩滞所以知道。", annotation: "面色缘缘正赤为阳气怫郁。发汗不彻则邪无出路，烦躁、不知痛处、脉涩为邪郁之征。更发汗则邪随汗解。" },
  { id: "SH-051", chapter: "辨太阳病脉证并治下", original: "脉浮数者，法当汗出而愈。若下之，身重心悸者，不可发汗，当自汗出乃解。所以然者，尺中脉微，此里虚，须表里实，津液自和，便自汗出愈。", translation: "脉象浮数的，照理应当发汗而痊愈。如果误用下法，导致身体沉重心悸的，不可再发汗，应当等待自汗出才能解除。之所以这样，是因为尺中脉微弱，这是里虚，必须等到表里充实，津液自然调和，就会自汗出而痊愈。", annotation: "脉浮数为表证当汗。误下后身重心悸为正气受损。尺中脉微为里阳虚。不可再发虚人之汗，待正气恢复自汗而解。" },
  { id: "SH-052", chapter: "辨太阳病脉证并治下", original: "脉浮紧者，法当身疼痛，宜以汗解之。假令尺中迟者，不可发汗。何以知然？以荣气不足，血少故也。", translation: "脉象浮紧的，照理应当身体疼痛，适宜用发汗解除。假使尺中脉迟的，不可发汗。怎么知道这样？因为营气不足，血少的缘故。", annotation: "脉浮紧身疼痛为麻黄汤证。但尺中脉迟为营血不足，发汗则更伤营血。此为挟虚伤寒，不可峻汗。" },
  { id: "SH-053", chapter: "辨太阳病脉证并治下", original: "脉浮者，病在表，可发汗，宜麻黄汤。", translation: "脉象浮的，病在表，可以发汗，适宜用麻黄汤。", annotation: "脉浮主表。但须无汗、恶寒、身痛等表实证方可与麻黄汤。若有汗脉浮缓则是桂枝汤证。" },
  { id: "SH-054", chapter: "辨太阳病脉证并治下", original: "脉浮而数者，可发汗，宜麻黄汤。", translation: "脉象浮而数的，可以发汗，适宜用麻黄汤。", annotation: "脉浮数为表有邪而正能抗邪。但必须是无汗表实方可与麻黄汤。" },
  { id: "SH-055", chapter: "辨太阳病脉证并治下", original: "病常自汗出者，此为荣气和。荣气和者，外不谐，以卫气不共荣气谐和故尔。以荣行脉中，卫行脉外。复发其汗，荣卫和则愈，宜桂枝汤。", translation: "病时常自汗出的，这是营气调和。营气调和而外不调和，是因为卫气不能与营气和谐的缘故。因为营气行于脉中，卫气行于脉外。再发其汗，营卫和谐就会痊愈，适宜用桂枝汤。", annotation: "自汗出为营卫不和。营气本和而卫气不固。桂枝汤调和营卫，发汗则营卫和谐而愈。此发汗非发汗解表，乃调营卫也。" },
  { id: "SH-056", chapter: "辨太阳病脉证并治下", original: "病人脏无他病，时发热自汗出而不愈者，此卫气不和也。先其时发汗则愈，宜桂枝汤。", translation: "病人内脏没有其他疾病，时而发热自汗出而不痊愈的，这是卫气不调和。在发热之前发汗就会痊愈，适宜用桂枝汤。", annotation: "脏无他病说明病不在里。时发热自汗为卫气时与营争。先其时发汗，使营卫预和。" },
  { id: "SH-057", chapter: "辨太阳病脉证并治下", original: "伤寒，脉浮紧，不发汗，因致衄者，麻黄汤主之。", translation: "伤寒，脉象浮紧，没有发汗，因而导致鼻出血的，用麻黄汤主治。", annotation: "伤寒表实当汗不汗，邪无从出，迫血妄行致衄。衄后表证仍在者，仍宜麻黄汤发汗解表。" },
  { id: "SH-058", chapter: "辨太阳病脉证并治下", original: "伤寒，不大便六七日，头痛有热者，与承气汤。其小便清者，知不在里，仍在表也，当须发汗。若头痛者，必衄。宜桂枝汤。", translation: "伤寒，不大便六七天，头痛有发热的，给予承气汤。如果小便清长的，知道病不在里，仍在表，应当发汗。如果头痛的，必定鼻出血。适宜用桂枝汤。", annotation: "不大便六七日有热似里证，但小便清知不在里。以小便辨表里，头痛为表证。宜桂枝汤解表。" },
  { id: "SH-059", chapter: "辨太阳病脉证并治下", original: "伤寒发汗已解，半日许复烦，脉浮数者，可更发汗，宜桂枝汤。", translation: "伤寒发汗后已解除，半天左右又烦躁，脉象浮数的，可以再发汗，适宜用桂枝汤。", annotation: "发汗后半日复烦脉浮数，为余邪未尽或复感外邪。宜桂枝汤微发其汗。" },
  { id: "SH-060", chapter: "辨太阳病脉证并治下", original: "凡病，若发汗，若吐，若下，若亡血，亡津液，阴阳自和者，必自愈。", translation: "凡是病，或发汗，或涌吐，或攻下，或失血，津液耗伤，如果阴阳自然调和的，必定自行痊愈。", annotation: "此为治疗总则。无论汗吐下亡血亡津，只要阴阳自和，正气渐复，病必自愈。不可妄攻。" },
  { id: "SH-061", chapter: "辨太阳病脉证并治下", original: "大下之后，复发汗，小便不利者，亡津液故也。勿治之，得小便利，必自愈。", translation: "大下之后，又发汗，小便不通利的，是津液耗伤的缘故。不要治疗，等到小便通利，必定自行痊愈。", annotation: "大下复发汗，津液大伤，小便不利为津亏。'勿治之'是说不要用利小便之药，待津液恢复小便自利。" },
  { id: "SH-062", chapter: "辨太阳病脉证并治下", original: "下之后，复发汗，必振寒，脉微细。所以然者，以内外俱虚故也。", translation: "攻下之后，又发汗，必定寒战怕冷，脉象微细。之所以这样，是因为表里都虚的缘故。", annotation: "下之伤里，发汗伤表，内外俱虚。振寒为阳虚，脉微细为阴阳两虚。" },
  { id: "SH-063", chapter: "辨太阳病脉证并治下", original: "下之后，复发汗，昼日烦躁不得眠，夜而安静，不呕不渴，无表证，脉沉微，身无大热者，干姜附子汤主之。", translation: "攻下之后，又发汗，白天烦躁不能安眠，夜间安静，不呕不渴，没有表证，脉象沉微，身体没有大热的，用干姜附子汤主治。", annotation: "昼日烦躁夜安静为阳虚。白昼阳旺时虚阳与阴争故烦，夜间阴盛虚阳不能争故静。干姜附子汤回阳破阴。" },
  { id: "SH-064", chapter: "辨太阳病脉证并治下", original: "发汗后，身疼痛，脉沉迟者，桂枝加芍药生姜各一两人参三两新加汤主之。", translation: "发汗后，身体疼痛，脉象沉迟的，用桂枝加芍药生姜各一两人参三两新加汤主治。", annotation: "发汗后身疼痛脉沉迟为营血不足、筋脉失养。新加汤（桂枝汤加芍药生姜人参）调和营卫、益气养血。" },
  { id: "SH-065", chapter: "辨太阳病脉证并治下", original: "发汗后，不可更行桂枝汤，汗出而喘，无大热者，可与麻黄杏仁甘草石膏汤。", translation: "发汗后，不可再用桂枝汤，汗出而喘，没有大热的，可以给予麻黄杏仁甘草石膏汤。", annotation: "汗后汗出而喘为邪热壅肺。无大热指表无大热，里有热。麻杏甘石汤清宣肺热。" },
  { id: "SH-066", chapter: "辨太阳病脉证并治下", original: "发汗过多，其人叉手自冒心，心下悸，欲得按者，桂枝甘草汤主之。", translation: "发汗过多，病人双手交叉按在心口上，胃脘部悸动，想要按压的，用桂枝甘草汤主治。", annotation: "汗为心之液，发汗过多心阳受损。叉手自冒心、心下悸欲按为心阳虚之征。桂枝甘草汤辛甘化阳、温通心阳。" },
  { id: "SH-067", chapter: "辨太阳病脉证并治下", original: "发汗后，其人脐下悸者，欲作奔豚，茯苓桂枝甘草大枣汤主之。", translation: "发汗后，病人脐下悸动的，是将要发作奔豚，用茯苓桂枝甘草大枣汤主治。", annotation: "汗后心阳虚，肾中水气欲上冲。脐下悸为水气欲动。苓桂枣甘汤温阳利水、平冲降逆。" },
  { id: "SH-068", chapter: "辨太阳病脉证并治下", original: "发汗后，腹胀满者，厚朴生姜半夏甘草人参汤主之。", translation: "发汗后，腹部胀满的，用厚朴生姜半夏甘草人参汤主治。", annotation: "发汗后脾虚气滞。厚朴、生姜、半夏理气除满，人参、甘草补中。消补兼施。" },
  { id: "SH-069", chapter: "辨太阳病脉证并治下", original: "伤寒，若吐若下后，心下逆满，气上冲胸，起则头眩，脉沉紧，发汗则动经，身为振振摇者，茯苓桂枝白术甘草汤主之。", translation: "伤寒，或吐或下后，胃脘部气逆胀满，气上冲胸，起立时头眩晕，脉象沉紧，再发汗就会扰动经脉，身体振颤摇动的，用茯苓桂枝白术甘草汤主治。", annotation: "吐下后脾虚水停，水气上冲。心下逆满、头眩、脉沉紧为水饮之征。苓桂术甘汤健脾利水、温阳化饮。" },
  { id: "SH-070", chapter: "辨太阳病脉证并治下", original: "发汗，病不解，反恶寒者，虚故也。芍药甘草附子汤主之。", translation: "发汗，病不解，反而怕冷的，是虚的缘故。用芍药甘草附子汤主治。", annotation: "汗后反恶寒为阳虚。芍药甘草养营缓急，附子温阳。阴阳两补。" },
  { id: "SH-071", chapter: "辨太阳病脉证并治下", original: "发汗，若下之，病仍不解，烦躁者，茯苓四逆汤主之。", translation: "发汗，或攻下，病仍然不解，烦躁的，用茯苓四逆汤主治。", annotation: "汗下后阴阳俱虚而烦躁。四逆汤回阳，茯苓宁心安神，人参益气。回阳益阴安神并举。" },
  { id: "SH-072", chapter: "辨太阳病脉证并治下", original: "太阳病，发汗后，大汗出，胃中干，烦躁不得眠，欲得饮水者，少少与饮之，令胃气和则愈。若脉浮，小便不利，微热消渴者，五苓散主之。", translation: "太阳病，发汗后，大汗出，胃中干燥，烦躁不能安眠，想要喝水的，少量多次给予饮水，使胃气调和就会痊愈。如果脉象浮，小便不通利，微热口渴饮水不解的，用五苓散主治。", annotation: "汗后胃干口渴为津伤，少少与饮之即可。若脉浮小便不利微热消渴为水停膀胱、气化不行，五苓散化气利水。" },
  { id: "SH-073", chapter: "辨太阳病脉证并治下", original: "发汗已，脉浮数，烦渴者，五苓散主之。", translation: "发汗后，脉象浮数，烦渴的，用五苓散主治。", annotation: "脉浮数为表未解，烦渴为水停不化津液。五苓散解表利水。" },
  { id: "SH-074", chapter: "辨太阳病脉证并治下", original: "伤寒，汗出而渴者，五苓散主之；不渴者，茯苓甘草汤主之。", translation: "伤寒，汗出而口渴的，用五苓散主治；不口渴的，用茯苓甘草汤主治。", annotation: "口渴与否为辨证要点。渴为水停下焦气化不利；不渴为水停中焦。五苓散主下焦水停，茯苓甘草汤主中焦水停。" },
  { id: "SH-075", chapter: "辨太阳病脉证并治下", original: "中风，发热，六七日不解而烦，有表里证，渴欲饮水，水入则吐者，名曰水逆，五苓散主之。", translation: "中风，发热，六七天不解而烦躁，既有表证又有里证，口渴想要喝水，水入就吐的，名叫水逆，用五苓散主治。", annotation: "发热为表证，烦渴水入则吐为里证（水饮内停）。水逆为水饮上逆拒水不纳。五苓散化气利水，水去则吐止。" },
  { id: "SH-076", chapter: "辨太阳病脉证并治下", original: "未持脉时，病人手叉自冒心，师因教试令咳，而不咳者，此必两耳聋无闻也。所以然者，以重发汗，虚故如此。发汗后，饮水多必喘，以水灌之亦喘。", translation: "没有诊脉时，病人双手交叉按在心口上，医生因而叫他试着咳嗽，而不咳嗽的，这必定是两耳聋听不到。之所以这样，是因为发汗太过，虚的缘故才会这样。发汗后，饮水过多必定气喘，用水浇洗也会气喘。", annotation: "重发汗伤心阳，心开窍于耳故耳聋。叉手自冒心为心阳虚。饮水多或水灌皆致水饮犯肺而喘。" },
  { id: "SH-077", chapter: "辨太阳病脉证并治下", original: "发汗后，水药不得入口为逆，若更发汗，必吐下不止。发汗吐下后，虚烦不得眠，若剧者，必反复颠倒，心中懊憹，栀子豉汤主之。", translation: "发汗后，水药不能入口是治疗错误，如果再发汗，必定吐泻不止。发汗吐下后，虚烦不能安眠，严重的必定反复辗转，心中烦闷不安，用栀子豉汤主治。", annotation: "水药不得入口为胃气大伤。发汗吐下后邪去正伤，余热留扰胸膈，故虚烦懊憹。栀子豉汤清宣郁热。" },
  { id: "SH-078", chapter: "辨太阳病脉证并治下", original: "若少气者，栀子甘草豉汤主之；若呕者，栀子生姜豉汤主之。", translation: "如果少气的，用栀子甘草豉汤主治；如果呕吐的，用栀子生姜豉汤主治。", annotation: "少气为气虚，加甘草益气。呕为胃气上逆，加生姜降逆止呕。随证加减之范例。" },
  { id: "SH-079", chapter: "辨太阳病脉证并治下", original: "发汗，若下之，而烦热胸中窒者，栀子豉汤主之。", translation: "发汗，或攻下，而烦热胸中窒塞的，用栀子豉汤主治。", annotation: "烦热胸中窒为郁热更甚，气机不畅。栀子豉汤清宣郁热，热清则气机自畅。" },
  { id: "SH-080", chapter: "辨太阳病脉证并治下", original: "伤寒五六日，大下之后，身热不去，心中结痛者，未欲解也，栀子豉汤主之。", translation: "伤寒五六天，大下之后，身热不去，心中结滞疼痛的，病还未解除，用栀子豉汤主治。", annotation: "大下后身热不去心中结痛，为余热与痰水结于胸膈。栀子豉汤清宣郁热、散结止痛。" },
  { id: "SH-081", chapter: "辨太阳病脉证并治下", original: "伤寒下后，心烦腹满，卧起不安者，栀子厚朴汤主之。", translation: "伤寒下后，心烦腹部胀满，坐卧不安的，用栀子厚朴汤主治。", annotation: "下后邪热内陷，扰于上则心烦，滞于中则腹满。栀子清热除烦，厚朴枳实理气除满。" },
  { id: "SH-082", chapter: "辨太阳病脉证并治下", original: "伤寒，医以丸药大下之，身热不去，微烦者，栀子干姜汤主之。", translation: "伤寒，医生用丸药大攻下，身热不去，微烦的，用栀子干姜汤主治。", annotation: "丸药大下伤中阳，身热微烦为上热中寒。栀子清上热，干姜温中寒。寒热并用。" },
  { id: "SH-083", chapter: "辨太阳病脉证并治下", original: "凡用栀子汤，病人旧微溏者，不可与服之。", translation: "凡是使用栀子汤，病人平素大便微溏的，不可给予服用。", annotation: "栀子苦寒伤胃，旧微溏为脾虚便溏，服之则更伤脾阳。此为栀子汤禁忌。" },
  { id: "SH-084", chapter: "辨太阳病脉证并治下", original: "太阳病发汗，汗出不解，其人仍发热，心下悸，头眩，身瞤动，振振欲擗地者，真武汤主之。", translation: "太阳病发汗，汗出病不解，病人仍然发热，胃脘部悸动，头眩晕，身体肌肉瞤动，振颤将要倒地的，用真武汤主治。", annotation: "汗后阳虚水泛。发热为虚阳外浮，心下悸、头眩、身瞤动为水气上冲。真武汤温阳利水。" },
  { id: "SH-085", chapter: "辨太阳病脉证并治下", original: "咽喉干燥者，不可发汗。", translation: "咽喉干燥的，不可发汗。", annotation: "咽喉干燥为阴津不足。发汗则更伤阴液，助热伤津。" },
  { id: "SH-086", chapter: "辨太阳病脉证并治下", original: "淋家，不可发汗，汗出必便血。", translation: "平素患淋病的人，不可发汗，汗出必定便血。", annotation: "淋家多下焦湿热阴伤。发汗则热迫血行而便血。" },
  { id: "SH-087", chapter: "辨太阳病脉证并治下", original: "疮家，虽身疼痛，不可发汗，汗出则痉。", translation: "平素患疮疡的人，虽然身体疼痛，不可发汗，汗出就会发痉。", annotation: "疮家多气血两伤。发汗则更伤津血，筋脉失养则痉。" },
  { id: "SH-088", chapter: "辨太阳病脉证并治下", original: "衄家，不可发汗，汗出必额上陷脉急紧，直视不能眴，不得眠。", translation: "平素常流鼻血的人，不可发汗，汗出必定额上陷脉拘紧急迫，眼睛直视不能转动，不能安眠。", annotation: "衄家多阴血虚。发汗则血更虚，经脉失养。额上陷脉急紧、直视不能眴为津血大亏之象。" },
  { id: "SH-089", chapter: "辨太阳病脉证并治下", original: "亡血家，不可发汗，发汗则寒栗而振。", translation: "平素失血的人，不可发汗，发汗就会寒战而振颤。", annotation: "亡血家气血两虚。发汗则阳随阴泄，寒栗而振。" },
  { id: "SH-090", chapter: "辨太阳病脉证并治下", original: "汗家，重发汗，必恍惚心乱，小便已阴疼，与禹余粮丸。", translation: "平素多汗的人，再发汗，必定精神恍惚心中烦乱，小便后阴部疼痛，给予禹余粮丸。", annotation: "汗家多阳虚。重发汗则心阳亦虚，心神失守故恍惚心乱。阴疼为津伤窍痛。禹余粮丸固涩止汗（方佚）。" },
  { id: "SH-091", chapter: "辨太阳病脉证并治下", original: "病人有寒，复发汗，胃中冷，必吐蛔。", translation: "病人有寒，又发汗，胃中寒冷，必定吐蛔虫。", annotation: "内有寒复发汗，胃阳更伤。胃冷蛔不安而上逆。" },
  { id: "SH-092", chapter: "辨太阳病脉证并治下", original: "本发汗而复下之，此为逆也；若先发汗，治不为逆。本先下之，而反汗之，为逆；若先下之，治不为逆。", translation: "本来应当发汗反而攻下，这是治疗错误；如果先发汗，治疗不算错误。本来应当先攻下反而发汗，是错误；如果先攻下，治疗不算错误。", annotation: "此条论述表里先后治则。表证为主先发汗，里证为主先攻下。逆其治则为误。" },
  { id: "SH-093", chapter: "辨太阳病脉证并治下", original: "伤寒，医下之，续得下利清谷不止，身疼痛者，急当救里；后身疼痛，清便自调者，急当救表。救里宜四逆汤，救表宜桂枝汤。", translation: "伤寒，医生攻下，接着泄泻不止，完谷不化，身体疼痛的，应当急救其里；后来身体疼痛，大小便恢复正常的，应当急救其表。救里适宜用四逆汤，救表适宜用桂枝汤。", annotation: "误下后下利清谷不止为里虚寒甚，身疼痛为表证未解。表里同病里证为急，当先救里。里和表不解再救表。" },
  { id: "SH-094", chapter: "辨太阳病脉证并治下", original: "病发热头痛，脉反沉，若不差，身体疼痛，当救其里，四逆汤方。", translation: "病发热头痛，脉象反沉，如果不痊愈，身体疼痛，应当救其里，用四逆汤方。", annotation: "发热头痛为表证，脉沉为里阳虚。此为表实里虚，当先温里。里阳复则表自解。" },
  { id: "SH-095", chapter: "辨太阳病脉证并治下", original: "太阳病，先下而不愈，因复发汗，以此表里俱虚，其人因致冒，冒家汗出自愈。所以然者，汗出表和故也。里未和，然后复下之。", translation: "太阳病，先用下法而不愈，因而又发汗，因此表里都虚，病人因而头目昏冒，昏冒的人汗出自愈。之所以这样，是因为汗出表和的缘故。里未和，然后再攻下。", annotation: "先下后汗致表里俱虚。冒为正虚邪郁。汗出表和自愈。里未和（便秘等）再下。" },
  { id: "SH-096", chapter: "辨太阳病脉证并治下", original: "太阳病未解，脉阴阳俱停，必先振栗，汗出而解。但阳脉微者，先汗出而解；但阴脉微者，下之而解。若欲下之，宜调胃承气汤。", translation: "太阳病未解，寸关尺脉象都隐伏不见，必定先寒战，然后汗出而解。只是寸脉微的，先发汗而解；只是尺脉微的，攻下而解。如果想要攻下，适宜用调胃承气汤。", annotation: "脉阴阳俱停为邪正剧争，脉道郁闭。战汗后脉出邪解。阳脉微为表欲解，阴脉微为里欲解。" },
  { id: "SH-097", chapter: "辨太阳病脉证并治下", original: "太阳病，发热汗出者，此为荣弱卫强，故使汗出，欲救邪风者，宜桂枝汤。", translation: "太阳病，发热汗出的，这是营气弱卫气强，所以使汗出，想要解除风邪的，适宜用桂枝汤。", annotation: "营弱卫强即营卫不和。桂枝汤调和营卫。" },
  { id: "SH-098", chapter: "辨太阳病脉证并治下", original: "伤寒五六日，中风，往来寒热，胸胁苦满，嘿嘿不欲饮食，心烦喜呕，或胸中烦而不呕，或渴，或腹中痛，或胁下痞硬，或心下悸、小便不利，或不渴、身有微热，或咳者，小柴胡汤主之。", translation: "伤寒五六天，中风，寒热往来，胸胁胀满不适，沉默不想饮食，心中烦闷喜欢呕吐，或者胸中烦闷而不呕，或者口渴，或者腹中疼痛，或者胁下痞硬，或者胃脘悸动、小便不通利，或者不渴、身体微热，或者咳嗽的，用小柴胡汤主治。", annotation: "小柴胡汤证为少阳病典型。往来寒热、胸胁苦满、默默不欲饮食、心烦喜呕为四大主症。或然症甚多，皆因邪入少阳，枢机不利所致。" },
  { id: "SH-099", chapter: "辨太阳病脉证并治下", original: "血弱气尽，腠理开，邪气因入，与正气相搏，结于胁下。正邪分争，往来寒热，休作有时，嘿嘿不欲饮食。脏腑相连，其痛必下，邪高痛下，故使呕也，小柴胡汤主之。", translation: "气血虚弱，腠理开泄，邪气因而侵入，与正气相搏，结于胁下。正邪相争，所以往来寒热，发作有时，沉默不想饮食。脏腑相连，疼痛必涉及下部，邪在上疼痛在下，所以使人呕吐，用小柴胡汤主治。", annotation: "此条解释小柴胡汤证病机。血弱气尽为正气不足，邪气乘虚入少阳。脏腑相连指肝胆脾胃相互关联，肝病传脾。" },
  { id: "SH-100", chapter: "辨太阳病脉证并治下", original: "服柴胡汤已，渴者，属阳明，以法治之。", translation: "服用柴胡汤后，口渴的，是转属阳明，按照相应方法治疗。", annotation: "服柴胡汤后渴为邪转阳明，应从阳明论治。" },
  { id: "SH-101", chapter: "辨太阳病脉证并治下", original: "得病六七日，脉迟浮弱，恶风寒，手足温。医二三下之，不能食，而胁下满痛，面目及身黄，颈项强，小便难者，与柴胡汤，后必下重。本渴饮水而呕者，柴胡汤不中与也，食谷者哕。", translation: "得病六七天，脉象迟浮弱，怕风寒，手足温暖。医生多次攻下，导致不能饮食，而胁下胀满疼痛，面目及身体发黄，颈项僵硬，小便困难的，给予柴胡汤，以后必定会下利后重。本来口渴饮水而呕吐的，柴胡汤不适合给予，进食后会呃逆。", annotation: "脉迟浮弱恶风寒手足温为太阴表证。误下脾虚寒湿郁滞发黄。此为寒湿发黄而非少阳证。柴胡汤苦寒不宜。" },
  { id: "SH-102", chapter: "辨太阳病脉证并治下", original: "太阳病，过经十余日，反二三下之，后四五日，柴胡证仍在者，先与小柴胡汤。呕不止，心下急，郁郁微烦者，为未解也，与大柴胡汤下之则愈。", translation: "太阳病，过经十多天，反而多次攻下，后四五天，柴胡证仍然存在的，先给予小柴胡汤。呕吐不止，胃脘部拘急，郁闷微烦的，是病未解，给予大柴胡汤攻下就会痊愈。", annotation: "过经十余日柴胡证仍在，先与小柴胡汤。呕不止心下急郁郁微烦为少阳兼阳明里实，大柴胡汤和解兼攻下。" },
  { id: "SH-103", chapter: "辨太阳病脉证并治下", original: "太阳病，过经十余日，心下温温欲吐，而胸中痛，大便反溏，腹微满，郁郁微烦。先此时自极吐下者，与调胃承气汤。若不尔者，不可与。但欲呕，胸中痛，微溏者，此非柴胡汤证，以呕故知极吐下也。", translation: "太阳病，过经十多天，胃脘部泛泛欲吐，而胸中疼痛，大便反而溏薄，腹部微满，郁闷微烦。在此之前曾用峻吐峻下的，给予调胃承气汤。如果不是这样的，不可给予。只是想呕吐，胸中疼痛，大便微溏的，这不是柴胡汤证，因为呕吐所以知道曾用峻吐峻下。", annotation: "心下温温欲吐、胸中痛、便溏、腹满、烦为误吐下后胃气不和。调胃承气汤调胃和中。但欲呕非少阳柴胡证。" },
  { id: "SH-104", chapter: "辨太阳病脉证并治下", original: "伤寒十三日不解，胸胁满而呕，日晡所发潮热，已而微利。此本柴胡证，下之以不得利，今反利者，知医以丸药下之，此非其治也。潮热者，实也。先宜服小柴胡汤以解外，后以柴胡加芒硝汤主之。", translation: "伤寒十三天不解，胸胁胀满而呕吐，午后定时发潮热，后来轻微下利。这本来是柴胡证，因为不得利而攻下，现在反而下利的，知道医生用丸药攻下，这不是正确的治疗。潮热是实证。先适宜服小柴胡汤以解表，后用柴胡加芒硝汤主治。", annotation: "胸胁满呕为柴胡证，日晡潮热为阳明实。本应大柴胡汤和解攻下，医以丸药下之不当。先服小柴胡汤解外，后柴胡加芒硝汤兼下。" },
  { id: "SH-105", chapter: "辨太阳病脉证并治下", original: "伤寒十三日，过经谵语者，以有热也，当以汤下之。若小便利者，大便当硬，而反下利，脉调和者，知医以丸药下之，非其治也。若自下利者，脉当微厥，今反和者，此为内实也，调胃承气汤主之。", translation: "伤寒十三天，过经说胡话的，是因为有热，应当用汤药攻下。如果小便通利的，大便应当硬，反而下利，脉象调和的，知道医生用丸药攻下，不是正确治疗。如果自行下利的，脉象应当微弱四肢厥冷，现在反而调和的，这是内实，用调胃承气汤主治。", annotation: "谵语有热当下。小便利大便当硬。反下利而脉调和为医以丸药下之不当。自下利脉当微厥，今反和为内实。" },
  { id: "SH-106", chapter: "辨太阳病脉证并治下", original: "太阳病不解，热结膀胱，其人如狂，血自下，下者愈。其外不解者，尚未可攻，当先解其外；外解已，但少腹急结者，乃可攻之，宜桃核承气汤。", translation: "太阳病不解，邪热结于膀胱，病人像发狂一样，瘀血自行下泄，下血的就会痊愈。如果表证未解除的，还不可以攻下，应当先解表；表证解除后，只有少腹拘急结硬的，才可以攻下，适宜用桃核承气汤。", annotation: "热结膀胱为太阳蓄血证轻证。如狂为瘀热扰心。血自下瘀热去则愈。先表后里。少腹急结为下焦瘀血证。桃核承气汤活血化瘀。" },
  { id: "SH-107", chapter: "辨太阳病脉证并治下", original: "伤寒八九日，下之，胸满烦惊，小便不利，谵语，一身尽重，不可转侧者，柴胡加龙骨牡蛎汤主之。", translation: "伤寒八九天，攻下，胸部胀满烦扰惊惕，小便不通利，说胡话，全身都沉重，不能转侧的，用柴胡加龙骨牡蛎汤主治。", annotation: "误下后邪陷少阳，三焦不利，心神被扰。胸满烦惊、谵语、身重不可转侧为柴胡加龙牡汤证。和解少阳、通阳泄热、重镇安神。" },
  { id: "SH-108", chapter: "辨太阳病脉证并治下", original: "伤寒，腹满谵语，寸口脉浮而紧，此肝乘脾也，名曰纵，刺期门。", translation: "伤寒，腹部胀满说胡话，寸口脉浮而紧，这是肝乘脾，名叫纵，针刺期门。", annotation: "腹满谵语似阳明实证，但脉浮紧为肝木克脾土。纵为顺，肝本克脾。刺期门泻肝。" },
  { id: "SH-109", chapter: "辨太阳病脉证并治下", original: "伤寒，发热，啬啬恶寒，大渴欲饮水，其腹必满，自汗出，小便利者，其病欲解，此肝乘肺也，名曰横，刺期门。", translation: "伤寒，发热，啬啬恶寒，大渴想喝水，腹部必定胀满，自汗出，小便通利的，病将要解除，这是肝乘肺，名叫横，针刺期门。", annotation: "肝乘肺为横，肝木本不克肺金，今反乘之，故曰横。自汗出小便利为邪有出路，病欲解。刺期门泻肝。" },
  { id: "SH-110", chapter: "辨太阳病脉证并治下", original: "太阳病二日，反躁，凡熨其背，而大汗出，大热入胃，胃中水竭，躁烦，必发谵语。十余日，振栗，自下利者，此为欲解也。故其汗从腰以下不得汗，欲小便不得，反呕，欲失溲，足下恶风，大便硬，小便当数而反不数及不多，大便已，头卓然而痛，其人足心必热，谷气下流故也。", translation: "太阳病二天，反而烦躁，用熨法熨其背，导致大汗出，大热入胃，胃中水液枯竭，烦躁，必定说胡话。十多天后，寒战，自行下利的，这是将要解除。所以汗从腰以下不得出汗，想要小便不得解，反而呕吐，想要遗尿，脚下怕风，大便硬，小便应当频数反而不频数也不多，大便后，头突然疼痛，病人足心必定发热，这是谷气下流的缘故。", annotation: "误用火法迫汗，大汗出伤津化燥致胃热谵语。十余日振栗自下利为阴液回复、正能抗邪。大便后头卓然而痛足心热为阳气下行通泰。" },
  { id: "SH-111", chapter: "辨太阳病脉证并治下", original: "太阳病中风，以火劫发汗，邪风被火热，血气流溢，失其常度。两阳相熏灼，其身发黄。阳盛则欲衄，阴虚小便难。阴阳俱虚竭，身体则枯燥，但头汗出，剂颈而还，腹满，微喘，口干咽烂，或不大便，久则谵语，甚者至哕，手足躁扰，捻衣摸床。小便利者，其人可治。", translation: "太阳病中风证，用火法强迫发汗，风邪被火热所迫，气血流行溢散，失去正常规律。风火两阳相互熏灼，身体发黄。阳盛则欲鼻出血，阴虚则小便困难。阴阳都虚竭，身体就枯燥，只有头部出汗，到颈部而止，腹部胀满，微喘，口干咽喉腐烂，或者不大便，日久就说胡话，严重的甚至呃逆，手足躁动不安，捻衣摸床。小便通利的，病人可以治疗。", annotation: "火劫发汗变证蜂起。两阳（风邪火邪）熏灼发黄。阳盛阴虚。阴阳俱虚则身体枯燥、头汗出。小便利为阴未尽竭，犹可治。" },
  { id: "SH-112", chapter: "辨太阳病脉证并治下", original: "伤寒脉浮，医以火迫劫之，亡阳，必惊狂，卧起不安者，桂枝去芍药加蜀漆牡蛎龙骨救逆汤主之。", translation: "伤寒脉象浮，医生用火法强迫发汗，导致亡阳，必定惊狂，坐卧不安的，用桂枝去芍药加蜀漆牡蛎龙骨救逆汤主治。", annotation: "火迫发汗亡阳，心神浮越。惊狂卧起不安为阳亡神散。救逆汤温阳安神、重镇涤痰。" },
  { id: "SH-113", chapter: "辨太阳病脉证并治下", original: "形作伤寒，其脉不弦紧而弱。弱者必渴，被火者必谵语。弱者发热，脉浮，解之，当汗出愈。", translation: "症状像伤寒，脉象不弦紧而弱。脉弱的必定口渴，被火攻的必定说胡话。脉弱发热而脉浮的，解除它，应当汗出而愈。", annotation: "脉弱非伤寒表实，乃温病之类。误火则热更盛而谵语。发热脉浮，仍可汗解，但宜辛凉。" },
  { id: "SH-114", chapter: "辨太阳病脉证并治下", original: "太阳病，以火熏之，不得汗，其人必躁。到经不解，必清血，名为火邪。", translation: "太阳病，用火熏法治疗，不得出汗，病人必定烦躁。到了经气应当解除的时候病不解，必定便血，名叫火邪。", annotation: "火熏不得汗，火邪内迫。到经不解为正气不复。火邪迫血下行便血。" },
  { id: "SH-115", chapter: "辨太阳病脉证并治下", original: "脉浮，热甚，而反灸之，此为实。实以虚治，因火而动，必咽燥，吐血。", translation: "脉象浮，发热很甚，反而用灸法，这是实证。实证当作虚证治，因火邪扰动，必定咽喉干燥，吐血。", annotation: "实热证误用温灸，火上加火。咽燥吐血为火迫血上溢。" },
  { id: "SH-116", chapter: "辨太阳病脉证并治下", original: "微数之脉，慎不可灸。因火为邪，则为烦逆，追虚逐实，血散脉中，火气虽微，内攻有力，焦骨伤筋，血难复也。脉浮，宜以汗解，用火灸之，邪无从出，因火而盛，病从腰以下必重而痹，名火逆也。欲自解者，必当先烦，烦乃有汗而解。何以知之？脉浮，故知汗出解。", translation: "微数的脉象，切不可用灸。因火成为邪气，就会烦躁气逆，正虚被追，邪实被逐，血液耗散在脉中，火气虽微小，内攻却有力，焦灼骨髓伤害筋脉，血液难以恢复。脉象浮，适宜发汗解表，用火灸，邪无从出，因火邪更盛，病从腰以下必定沉重而痹，名叫火逆。想要自行解除的，必定先烦，烦后才有汗出而解。怎么知道这样？脉浮，所以知道汗出而解。", annotation: "微数脉为阴虚有热，灸之则火邪更盛。焦骨伤筋为火逆重证。腰以下重痹为火逆致气机不通。" },
  { id: "SH-117", chapter: "辨太阳病脉证并治下", original: "烧针令其汗，针处被寒，核起而赤者，必发奔豚。气从少腹上冲心者，灸其核上各一壮，与桂枝加桂汤，更加桂二两也。", translation: "用烧针使病人出汗，针处受寒，核起而发红的，必定发作奔豚。气从少腹上冲心的，艾灸其核上各一壮，给予桂枝加桂汤，再加桂枝二两。", annotation: "烧针迫汗心阳受损，针处受寒核赤。奔豚为肾中水气乘虚上冲。灸核散寒。桂枝加桂汤温阳平冲。" },
  { id: "SH-118", chapter: "辨太阳病脉证并治下", original: "火逆下之，因烧针烦躁者，桂枝甘草龙骨牡蛎汤主之。", translation: "火逆后又攻下，因烧针而烦躁的，用桂枝甘草龙骨牡蛎汤主治。", annotation: "火逆复下，心阳大伤，心神浮越。烦躁为阳虚心神不敛。桂甘龙牡汤温阳安神。" },
  { id: "SH-119", chapter: "辨太阳病脉证并治下", original: "太阳伤寒者，加温针，必惊也。", translation: "太阳伤寒证，加用温针，必定惊惕。", annotation: "温针助热，火邪扰心。伤寒表实应以麻黄汤发汗，温针非所宜。" },
  { id: "SH-120", chapter: "辨太阳病脉证并治下", original: "太阳病，当恶寒发热，今自汗出，反不恶寒发热，关上脉细数者，以医吐之过也。一二日吐之者，腹中饥，口不能食；三四日吐之者，不喜糜粥，欲食冷食，朝食暮吐。以医吐之所致也，此为小逆。", translation: "太阳病，应当恶寒发热，现在自汗出，反而不恶寒发热，关脉细数的，是因为医生用吐法的过错。一二日用吐法的，腹中饥饿，口不能食；三四日用吐法的，不喜欢粥糜，想要吃冷食，早上吃晚上吐。因为医生用吐法所导致，这是小的错误。", annotation: "误吐伤胃气胃阴。自汗出不恶寒发热为表邪去而胃伤。关上脉细数为脾胃虚而有热。饥不能食、欲冷食朝食暮吐为胃虚有热。" },
  { id: "SH-121", chapter: "辨太阳病脉证并治下", original: "太阳病吐之，但太阳病当恶寒，今反不恶寒，不欲近衣，此为吐之内烦也。", translation: "太阳病用吐法后，太阳病应当恶寒，现在反而不恶寒，不想靠近衣服，这是吐法所致的内烦。", annotation: "误吐后表去而胃热内生。不恶寒不欲近衣为内热。" },
  { id: "SH-122", chapter: "辨太阳病脉证并治下", original: "病人脉数，数为热，当消谷引食，而反吐者，此以发汗，令阳气微，膈气虚，脉乃数也。数为客热，不能消谷，以胃中虚冷，故吐也。", translation: "病人脉象数，数为有热，应当消化谷物多食，反而呕吐的，这是因为发汗，使阳气微弱，膈间气虚，脉象才数。数是假热，不能消化谷物，因为胃中虚冷，所以呕吐。", annotation: "脉数为虚阳外浮之客热，非实热。胃中虚冷不能消谷故吐。此为真寒假热之脉。" },
  { id: "SH-123", chapter: "辨太阳病脉证并治下", original: "太阳病，过经十余日，心下温温欲吐，而胸中痛，大便反溏，腹微满，郁郁微烦。先此时自极吐下者，与调胃承气汤。若不尔者，不可与。但欲呕，胸中痛，微溏者，此非柴胡汤证，以呕故知极吐下也。", translation: "太阳病，过经十多天，胃脘部泛泛欲吐，而胸中疼痛，大便反而溏薄，腹部微满，郁闷微烦。在此之前曾用峻吐峻下的，给予调胃承气汤。如果不是这样的，不可给予。只是想呕吐，胸中疼痛，大便微溏的，这不是柴胡汤证，因为呕吐所以知道曾用峻吐峻下。", annotation: "误吐下后胃气不和。调胃承气汤调胃。但欲呕胸中痛非少阳柴胡汤证。" },
  { id: "SH-124", chapter: "辨太阳病脉证并治下", original: "太阳病六七日，表证仍在，脉微而沉，反不结胸，其人发狂者，以热在下焦，少腹当硬满，小便自利者，下血乃愈。所以然者，以太阳随经，瘀热在里故也。抵当汤主之。", translation: "太阳病六七天，表证仍在，脉象微而沉，反而不结胸，病人发狂的，是因为热在下焦，少腹应当硬满，小便自利的，下血才愈。之所以这样，是因为太阳经邪随经入里，瘀热在里的缘故。用抵当汤主治。", annotation: "太阳蓄血重证。表证仍在脉微而沉，邪陷入里。发狂为瘀热扰心较重。少腹硬满小便自利为蓄血辨证要点（与蓄水小便不利鉴别）。抵当汤破血逐瘀。" },
  { id: "SH-125", chapter: "辨太阳病脉证并治下", original: "太阳病，身黄，脉沉结，少腹硬，小便不利者，为无血也。小便自利，其人如狂者，血证谛也，抵当汤主之。", translation: "太阳病，身体发黄，脉象沉结，少腹硬满，小便不利的，是没有瘀血。小便自利，病人像发狂的，是瘀血证的确切表现，用抵当汤主治。", annotation: "身黄、脉沉结、少腹硬可见于蓄水亦可见于蓄血。小便不利为蓄水，小便自利如狂为蓄血。以此鉴别。" },
  { id: "SH-126", chapter: "辨太阳病脉证并治下", original: "伤寒有热，少腹满，应小便不利，今反利者，为有血也，当下之，不可余药，宜抵当丸。", translation: "伤寒有发热，少腹胀满，应当小便不利，现在反而通利的，是有瘀血，应当攻下，不可用其他药物，适宜用抵当丸。", annotation: "有热少腹满小便自利为蓄血轻证。抵当丸为丸剂，攻下较缓。" },
  { id: "SH-127", chapter: "辨太阳病脉证并治下", original: "太阳病，小便利者，以饮水多，必心下悸；小便少者，必苦里急也。", translation: "太阳病，小便通利的，因为饮水多，必定胃脘部悸动；小便少的，必定苦于少腹里急。", annotation: "小便利饮水多为水停中焦致心下悸。小便少为水停下焦致少腹里急。" },
  { id: "SH-128", chapter: "辨太阳病脉证并治下", original: "问曰：病有结胸，有脏结，其状何如？答曰：按之痛，寸脉浮，关脉沉，名曰结胸也。", translation: "问道：病有结胸，有脏结，症状如何？回答说：按之疼痛，寸脉浮，关脉沉，名叫结胸。", annotation: "结胸为邪与水饮结于胸膈。按之痛为实证。寸浮为阳邪在上，关沉为水饮结于中。" },
  { id: "SH-129", chapter: "辨太阳病脉证并治下", original: "何谓脏结？答曰：如结胸状，饮食如故，时时下利，寸脉浮，关脉小细沉紧，名曰脏结。舌上白胎滑者，难治。", translation: "什么叫脏结？回答说：像结胸的症状，饮食照常，时时下利，寸脉浮，关脉小细沉紧，名叫脏结。舌上白苔滑的，难治。", annotation: "脏结为脏气虚寒，阴寒凝结。如结胸状但饮食如故下利为异。关脉小细沉紧为虚寒凝结。白苔滑为阳虚寒甚，难治。" },
  { id: "SH-130", chapter: "辨太阳病脉证并治下", original: "脏结无阳证，不往来寒热，其人反静，舌上胎滑者，不可攻也。", translation: "脏结没有阳证，不往来寒热，病人反而安静，舌上苔滑的，不可攻下。", annotation: "脏结纯阴无阳。不往来寒热无少阳。反静无热。苔滑虚寒。不可攻。" },
  { id: "SH-131", chapter: "辨太阳病脉证并治下", original: "病发于阳，而反下之，热入因作结胸；病发于阴，而反下之，因作痞也。所以成结胸者，以下之太早故也。结胸者，项亦强，如柔痉状，下之则和，宜大陷胸丸。", translation: "病发于阳经（太阳），反而攻下，热邪内入因而形成结胸；病发于阴经（少阴），反而攻下，因而形成痞证。之所以形成结胸，是因为攻下太早的缘故。结胸证，项部也僵硬，像柔痉的样子，攻下就会调和，适宜用大陷胸丸。", annotation: "病发于阳（太阳病）误下热入与水结为结胸。病发于阴（少阴）误下胃气伤而痞。结胸项强如柔痉为水热结甚。大陷胸丸峻药缓攻。" },
  { id: "SH-132", chapter: "辨太阳病脉证并治下", original: "结胸证，其脉浮大者，不可下，下之则死。", translation: "结胸证，脉象浮大的，不可攻下，攻下就会死亡。", annotation: "脉浮大为邪尚在表或正虚邪实。下之则正气脱。结胸脉当沉紧，浮大非其所宜。" },
  { id: "SH-133", chapter: "辨太阳病脉证并治下", original: "结胸证悉具，烦躁者亦死。", translation: "结胸证的症状都具备了，烦躁的也会死。", annotation: "结胸证悉具为邪实壅盛。烦躁为正不胜邪、正气散乱。邪实正脱故死。" },
  { id: "SH-134", chapter: "辨太阳病脉证并治下", original: "太阳病，脉浮而动数，浮则为风，数则为热，动则为痛，数则为虚。头痛发热，微盗汗出，而反恶寒者，表未解也。医反下之，动数变迟，膈内拒痛，胃中空虚，客气动膈，短气躁烦，心中懊憹，阳气内陷，心下因硬，则为结胸，大陷胸汤主之。若不结胸，但头汗出，余处无汗，剂颈而还，小便不利，身必发黄。", translation: "太阳病，脉象浮而动数，浮是风邪，数是热，动是痛，数是虚。头痛发热，微微盗汗出，反而怕冷的，是表邪未解。医生反而攻下，动数脉变迟，膈间疼痛拒按，胃中虚空，邪气扰动胸膈，短气烦躁，心中懊憹，阳气内陷，胃脘部因而硬满，就成为结胸，用大陷胸汤主治。如果不结胸，只有头部出汗，别处无汗，到颈部而止，小便不利，身体必定发黄。", annotation: "脉浮动数为表有邪。误下后阳邪内陷与水结为结胸。大陷胸汤泻热逐水。不结胸则湿热郁蒸发黄，头汗出小便不利为发黄之征。" },
  { id: "SH-135", chapter: "辨太阳病脉证并治下", original: "伤寒六七日，结胸热实，脉沉而紧，心下痛，按之石硬者，大陷胸汤主之。", translation: "伤寒六七天，结胸热实证，脉象沉而紧，胃脘部疼痛，按之像石头一样硬的，用大陷胸汤主治。", annotation: "结胸典型表现：脉沉紧、心下痛、按之石硬。为水热互结之实证。大陷胸汤（大黄、芒硝、甘遂）泻热逐水破结。" },
  { id: "SH-136", chapter: "辨太阳病脉证并治下", original: "伤寒十余日，热结在里，复往来寒热者，与大柴胡汤。但结胸，无大热者，此为水结在胸胁也。但头微汗出者，大陷胸汤主之。", translation: "伤寒十多天，热结在里，又往来寒热的，给予大柴胡汤。只有结胸，没有大热的，这是水结在胸胁。只有头部微汗出的，用大陷胸汤主治。", annotation: "热结在里兼往来寒热为少阳阳明合病，大柴胡汤主之。结胸无大热为水热结。头微汗出为热不得外越。" },
  { id: "SH-137", chapter: "辨太阳病脉证并治下", original: "太阳病，重发汗而复下之，不大便五六日，舌上燥而渴，日晡所小有潮热，从心下至少腹硬满而痛，不可近者，大陷胸汤主之。", translation: "太阳病，重复发汗又攻下，不大便五六天，舌上干燥而口渴，午后稍有定时发热，从胃脘部至少腹硬满而疼痛，不可触碰的，用大陷胸汤主治。", annotation: "汗下后津伤热结。不大便、舌燥而渴、潮热似阳明，但心下至少腹硬满痛不可近为结胸。大陷胸汤主之。" },
  { id: "SH-138", chapter: "辨太阳病脉证并治下", original: "小结胸病，正在心下，按之则痛，脉浮滑者，小陷胸汤主之。", translation: "小结胸病，正在胃脘部，按之就疼痛，脉象浮滑的，用小陷胸汤主治。", annotation: "小结胸为痰热结于心下。按之则痛为病轻。脉浮滑为痰热之征。小陷胸汤（黄连、半夏、瓜蒌实）清热化痰开结。" },
  { id: "SH-139", chapter: "辨太阳病脉证并治下", original: "太阳病二三日，不能卧，但欲起，心下必结，脉微弱者，此本有寒分也。反下之，若利止，必作结胸；未止者，四日复下之，此作协热利也。", translation: "太阳病二三天，不能卧，只想起坐，胃脘部必定结滞，脉象微弱的，这本来有寒饮。反而攻下，如果下利止，必定形成结胸；下利未止的，四天后又攻下，这就形成协热利。", annotation: "不能卧但欲起为水饮停于心下。脉微弱本有寒分。误下后变证。利止邪结为结胸。利不止为协热利。" },
  { id: "SH-140", chapter: "辨太阳病脉证并治下", original: "太阳病，下之，其脉促，不结胸者，此为欲解也。脉浮者，必结胸。脉紧者，必咽痛。脉弦者，必两胁拘急。脉细数者，头痛未止。脉沉紧者，必欲呕。脉沉滑者，协热利。脉浮滑者，必下血。", translation: "太阳病，攻下后，脉象急促，不结胸的，这是将要解除。脉象浮的，必定结胸。脉象紧的，必定咽喉疼痛。脉象弦的，必定两胁拘急。脉象细数的，头痛未止。脉象沉紧的，必定呕吐。脉象沉滑的，协热利。脉象浮滑的，必定下血。", annotation: "此条以脉测证。脉促为正气抗邪。脉浮为阳邪在上。脉紧为寒邪。脉弦主肝。脉细数为阴虚有热。脉沉紧为里寒。脉沉滑为湿热。脉浮滑为血热。" },
  { id: "SH-141", chapter: "辨太阳病脉证并治下", original: "病在阳，应以汗解之，反以冷水潠之，若灌之，其热被劫不得去，弥更益烦，肉上粟起，意欲饮水，反不渴者，服文蛤散。若不差者，与五苓散。", translation: "病在阳（表），应当发汗解除，反而用冷水喷洒，或灌洗，邪热被阻不得外出，更加烦躁，皮肤上起粟粒，想要喝水，反而不渴的，服用文蛤散。如果不愈的，给予五苓散。", annotation: "冷水潠灌使表寒内热。肉上粟起为寒束于外。意欲饮水反不渴为内热不甚。文蛤散清湿热。不差与五苓散化气利水。" },
  { id: "SH-142", chapter: "辨太阳病脉证并治下", original: "太阳与少阳并病，头项强痛，或眩冒，时如结胸，心下痞硬者，当刺大椎第一间、肺俞、肝俞，慎不可发汗。发汗则谵语，脉弦。五日谵语不止，当刺期门。", translation: "太阳与少阳并病，头项僵硬疼痛，或目眩昏蒙，有时像结胸，胃脘部痞硬的，应当针刺大椎、肺俞、肝俞，切不可发汗。发汗就会说胡话，脉象弦。五天说胡话不止，应当针刺期门。", annotation: "太阳少阳并病。头项强痛为太阳，眩冒心下痞硬为少阳。刺大椎肺俞解太阳表，刺肝俞解少阳。误汗则津伤热盛谵语。刺期门泻肝。" },
  { id: "SH-143", chapter: "辨太阳病脉证并治下", original: "妇人中风，发热恶寒，经水适来，得之七八日，热除而脉迟，身凉，胸胁下满，如结胸状，谵语者，此为热入血室也，当刺期门，随其实而取之。", translation: "妇人中风，发热恶寒，月经正来，得病七八天，发热退而脉迟，身体凉，胸胁下胀满，像结胸的样子，说胡话的，这是热入血室，应当针刺期门，随其实而泻之。", annotation: "妇人经水适来表热乘虚入血室。热除脉迟身凉似表解，而胸胁满谵语为热入血室。刺期门泻肝，血室隶于肝。" },
  { id: "SH-144", chapter: "辨太阳病脉证并治下", original: "妇人中风，七八日续得寒热，发作有时，经水适断者，此为热入血室，其血必结，故使如疟状，发作有时，小柴胡汤主之。", translation: "妇人中风，七八天继续出现寒热，发作有时，月经正停止的，这是热入血室，经血必定结滞，所以使症状像疟疾，发作有时，用小柴胡汤主治。", annotation: "经水适断为血室空虚，热入与血结。寒热如疟发作有时为少阳枢机不利。小柴胡汤和解少阳，使热邪外达。" },
  { id: "SH-145", chapter: "辨太阳病脉证并治下", original: "妇人伤寒，发热，经水适来，昼日明了，暮则谵语，如见鬼状者，此为热入血室。无犯胃气，及上二焦，必自愈。", translation: "妇人伤寒，发热，月经正来，白天神志清楚，晚间就说胡话，像见到鬼的样子，这是热入血室。不要侵犯胃气及上二焦，必定自愈。", annotation: "经水适来热入血室。昼了暮谵为血室属阴，夜间阴盛之时热邪扰血。无犯胃气及上二焦，待经尽热随血去自愈。" },
  { id: "SH-146", chapter: "辨太阳病脉证并治下", original: "伤寒六七日，发热微恶寒，支节烦疼，微呕，心下支结，外证未去者，柴胡桂枝汤主之。", translation: "伤寒六七天，发热微怕冷，四肢关节烦疼，微呕，胃脘部支结，表证未去的，用柴胡桂枝汤主治。", annotation: "发热微恶寒支节烦疼为太阳表证。微呕心下支结为少阳证。太阳少阳并病较轻。柴胡桂枝汤各取半量和解发表。" },
  { id: "SH-147", chapter: "辨太阳病脉证并治下", original: "伤寒五六日，已发汗而复下之，胸胁满微结，小便不利，渴而不呕，但头汗出，往来寒热，心烦者，此为未解也，柴胡桂枝干姜汤主之。", translation: "伤寒五六天，已经发汗又攻下，胸胁胀满微结，小便不利，口渴而不呕，只有头部出汗，往来寒热，心烦的，这是病未解，用柴胡桂枝干姜汤主治。", annotation: "汗下后邪入少阳兼水饮内停。胸胁满、往来寒热、心烦为少阳。小便不利、渴、头汗出为水饮不化。柴胡桂枝干姜汤和解少阳、温化水饮。" },
  { id: "SH-148", chapter: "辨太阳病脉证并治下", original: "伤寒五六日，头汗出，微恶寒，手足冷，心下满，口不欲食，大便硬，脉细者，此为阳微结，必有表，复有里也。脉沉，亦在里也。汗出为阳微，假令纯阴结，不得复有外证，悉入在里，此为半在里半在外也。脉虽沉紧，不得为少阴病，所以然者，阴不得有汗，今头汗出，故知非少阴也，可与小柴胡汤。设不了了者，得屎而解。", translation: "伤寒五六天，头部出汗，微怕冷，手足冷，胃脘部胀满，口不想食，大便硬，脉象细的，这是阳气微结，必定有表证，又有里证。脉沉也属里。汗出为阳微，假使纯阴结，不会再有表证，全入在里，这是半在里半在外。脉虽沉紧，不能作为少阴病，之所以这样，阴证不得有汗，现在头部出汗，所以知道不是少阴，可以给予小柴胡汤。假设仍不爽快的，得大便通而解。", annotation: "此条论阳微结与纯阴结鉴别。阳微结为阳气郁结不甚，半表半里。头汗出为阳郁。微恶寒手足冷似少阴，但有汗出非少阴。与小柴胡汤枢转气机。" },
  { id: "SH-149", chapter: "辨太阳病脉证并治下", original: "伤寒五六日，呕而发热者，柴胡汤证具，而以他药下之，柴胡证仍在者，复与柴胡汤。此虽已下之，不为逆，必蒸蒸而振，却发热汗出而解。若心下满而硬痛者，此为结胸也，大陷胸汤主之。但满而不痛者，此为痞，柴胡不中与之，宜半夏泻心汤。", translation: "伤寒五六天，呕吐而发热的，柴胡汤证具备，而用其他药攻下，柴胡证仍在的，再给予柴胡汤。这虽然已经攻下，不算错误，必定蒸蒸而振战，然后发热汗出而解。如果胃脘部胀满而硬痛的，这是结胸，用大陷胸汤主治。只胀满而不痛的，这是痞证，柴胡汤不适合给予，适宜用半夏泻心汤。", annotation: "柴胡证误下后有三变：柴胡证仍在者复与柴胡汤，战汗而解；心下满硬痛为结胸，大陷胸汤；但满不痛为痞，半夏泻心汤。" },
  { id: "SH-150", chapter: "辨太阳病脉证并治下", original: "太阳少阳并病，而反下之，成结胸，心下硬，下利不止，水浆不下，其人心烦。", translation: "太阳少阳并病，反而攻下，形成结胸，胃脘部硬满，下利不止，水浆不入，病人心烦。", annotation: "并病误下成结胸。心下硬为结胸。下利不止水浆不下为胃气大伤。心烦为正虚邪盛。此为难治之证。" },
  { id: "SH-151", chapter: "辨太阳病脉证并治下", original: "脉浮而紧，而复下之，紧反入里，则作痞。按之自濡，但气痞耳。", translation: "脉象浮而紧，反而攻下，紧脉反而入里，就形成痞证。按之柔软，只是气痞而已。", annotation: "脉浮紧为伤寒表实，误下邪陷入里。心下痞按之濡为气痞，无形之气结。" },
  { id: "SH-152", chapter: "辨太阳病脉证并治下", original: "太阳中风，下利呕逆，表解者，乃可攻之。其人漐漐汗出，发作有时，头痛，心下痞硬满，引胁下痛，干呕短气，汗出不恶寒者，此表解里未和也，十枣汤主之。", translation: "太阳中风证，下利呕吐气逆，表证解除的，才可攻下。病人微微汗出，发作有时，头痛，胃脘部痞硬满，牵引胁下疼痛，干呕短气，汗出不恶寒的，这是表解里未和，用十枣汤主治。", annotation: "此为悬饮证。汗出不恶寒为表解。心下痞硬满引胁下痛为水停胸胁。十枣汤（芫花、甘遂、大戟、大枣）峻逐水饮。" },
  { id: "SH-153", chapter: "辨太阳病脉证并治下", original: "太阳病，医发汗，遂发热恶寒，因复下之，心下痞，表里俱虚，阴阳气并竭，无阳则阴独，复加烧针，因胸烦，面色青黄，肤瞤者，难治。今色微黄，手足温者，易愈。", translation: "太阳病，医生发汗，于是发热恶寒，因而又攻下，胃脘部痞，表里都虚，阴阳气都衰竭，无阳则阴独存，又加用烧针，因而胸中烦，面色青黄，肌肉瞤动的，难治。现在面色微黄，手足温暖的，容易痊愈。", annotation: "汗下复烧针，阴阳俱伤。面色青黄肤瞤为肝脾两伤，难治。色微黄手足温为脾胃气尚在，易愈。" },
  { id: "SH-154", chapter: "辨太阳病脉证并治下", original: "心下痞，按之濡，其脉关上浮者，大黄黄连泻心汤主之。", translation: "胃脘部痞塞，按之柔软，脉象在关部浮的，用大黄黄连泻心汤主治。", annotation: "此为热痞。按之濡为气痞非实结。关上浮为中焦有热。大黄黄连泻心汤清热消痞。" },
  { id: "SH-155", chapter: "辨太阳病脉证并治下", original: "心下痞，而复恶寒汗出者，附子泻心汤主之。", translation: "胃脘部痞塞，又怕冷汗出的，用附子泻心汤主治。", annotation: "此为热痞兼阳虚。心下痞为热，恶寒汗出为卫阳不足。附子泻心汤（大黄、黄连、黄芩、附子）清热泻痞兼扶阳。" },
  { id: "SH-156", chapter: "辨太阳病脉证并治下", original: "本以下之，故心下痞，与泻心汤。痞不解，其人渴而口燥烦，小便不利者，五苓散主之。", translation: "本来因为攻下，所以胃脘部痞塞，给予泻心汤。痞仍不解，病人口渴而口燥烦躁，小便不通利的，用五苓散主治。", annotation: "误下致痞，予泻心汤不解。渴而口燥烦小便不利为水停心下、气化不行。五苓散化气利水，水去痞自解。" },
  { id: "SH-157", chapter: "辨太阳病脉证并治下", original: "伤寒汗出，解之后，胃中不和，心下痞硬，干噫食臭，胁下有水气，腹中雷鸣，下利者，生姜泻心汤主之。", translation: "伤寒汗出，病解之后，胃中不和，胃脘部痞硬，嗳气有食臭味，胁下有水气，腹中雷鸣，下利的，用生姜泻心汤主治。", annotation: "汗后胃虚，饮食不化，水湿内生。心下痞硬、干噫食臭为胃虚食滞。胁下水气、腹中雷鸣下利为水湿下注。生姜泻心汤和胃消痞、散水止利。" },
  { id: "SH-158", chapter: "辨太阳病脉证并治下", original: "伤寒中风，医反下之，其人下利日数十行，谷不化，腹中雷鸣，心下痞硬而满，干呕，心烦不得安。医见心下痞，谓病不尽，复下之，其痞益甚。此非结热，但以胃中虚，客气上逆，故使硬也，甘草泻心汤主之。", translation: "伤寒或中风，医生反而攻下，病人下利一天数十次，完谷不化，腹中雷鸣，胃脘部痞硬而满，干呕，心烦不得安。医生见心下痞，说病未尽，又攻下，痞更甚。这不是热结，只是因为胃中虚，邪气上逆，所以使痞硬，用甘草泻心汤主治。", annotation: "误下后脾胃大伤，寒热错杂。下利、腹中雷鸣、心下痞硬、干呕心烦为典型表现。复下更伤胃。甘草泻心汤重用甘草，和胃补中、消痞止利。" },
  { id: "SH-159", chapter: "辨太阳病脉证并治下", original: "伤寒，服汤药，下利不止，心下痞硬。服泻心汤已，复以他药下之，利不止。医以理中与之，利益甚。理中者，理中焦，此利在下焦，赤石脂禹余粮汤主之。复不止者，当利其小便。", translation: "伤寒，服用汤药，下利不止，胃脘部痞硬。服用泻心汤后，又用其他药攻下，下利不止。医生用理中汤给予，下利更甚。理中汤是调理中焦的，这个利在下焦，用赤石脂禹余粮汤主治。再不止的，应当利其小便。", annotation: "此条辨下利辨证论治。误下后利不止，服泻心汤、理中汤不效，为下焦滑脱。赤石脂禹余粮汤涩肠固脱。再不止当分利小便。" },
  { id: "SH-160", chapter: "辨太阳病脉证并治下", original: "伤寒吐下后，发汗，虚烦，脉甚微，八九日心下痞硬，胁下痛，气上冲咽喉，眩冒，经脉动惕者，久而成痿。", translation: "伤寒吐下后，又发汗，虚烦，脉象很微弱，八九天后胃脘部痞硬，胁下疼痛，气上冲咽喉，头目昏眩，经脉跳动惕动的，日久就会成为痿证。", annotation: "吐下发汗后阴阳俱虚。虚烦脉微为正虚。心下痞硬、胁痛、气上冲、眩冒、经脉动惕为水气上冲。久则经脉失养成痿。" },
  { id: "SH-161", chapter: "辨太阳病脉证并治下", original: "伤寒发汗，若吐若下，解后，心下痞硬，噫气不除者，旋覆代赭汤主之。", translation: "伤寒发汗，或吐或下，病解后，胃脘部痞硬，嗳气不止的，用旋覆代赭汤主治。", annotation: "病解后胃虚气逆。心下痞硬、噫气不除为胃虚痰阻气逆。旋覆代赭汤和胃化痰、降逆止噫。" },
  { id: "SH-162", chapter: "辨太阳病脉证并治下", original: "下后，不可更行桂枝汤。若汗出而喘，无大热者，可与麻黄杏子甘草石膏汤。", translation: "攻下后，不可再用桂枝汤。如果汗出而喘，无大热的，可以给予麻黄杏子甘草石膏汤。", annotation: "下后邪热壅肺。汗出而喘、无大热为里热壅肺。麻杏甘石汤清宣肺热。此条与63条同。" },
  { id: "SH-163", chapter: "辨太阳病脉证并治下", original: "太阳病，外证未除，而数下之，遂协热而利，利下不止，心下痞硬，表里不解者，桂枝人参汤主之。", translation: "太阳病，表证未除，而屡次攻下，于是协热而利，下利不止，胃脘部痞硬，表里都不解的，用桂枝人参汤主治。", annotation: "误下后太阴虚寒兼表未解。协热利为里寒挟表热而下利。心下痞硬为太阴脾虚。桂枝人参汤（桂枝、人参、白术、干姜、甘草）温中解表。" },
  { id: "SH-164", chapter: "辨太阳病脉证并治下", original: "伤寒大下后，复发汗，心下痞，恶寒者，表未解也，不可攻痞，当先解表，表解乃可攻痞。解表宜桂枝汤，攻痞宜大黄黄连泻心汤。", translation: "伤寒大下后，又发汗，胃脘部痞塞，怕冷的，是表邪未解，不可攻痞，应当先解表，表解才可攻痞。解表适宜用桂枝汤，攻痞适宜用大黄黄连泻心汤。", annotation: "痞兼表证，先表后里。恶寒为表未解。表解乃攻痞。" },
  { id: "SH-165", chapter: "辨太阳病脉证并治下", original: "伤寒发热，汗出不解，心中痞硬，呕吐而下利者，大柴胡汤主之。", translation: "伤寒发热，汗出而病不解，心中痞硬，呕吐而下利的，用大柴胡汤主治。", annotation: "发热汗出不解为表里同病。心中痞硬、呕吐下利为少阳阳明合病。大柴胡汤和解少阳、泻下阳明。" },
  { id: "SH-166", chapter: "辨太阳病脉证并治下", original: "病如桂枝证，头不痛，项不强，寸脉微浮，胸中痞硬，气上冲咽喉不得息者，此为胸有寒也。当吐之，宜瓜蒂散。", translation: "病像桂枝汤证，头不痛，项不强，寸脉微浮，胸中痞硬，气上冲咽喉不得呼吸的，这是胸中有寒痰。应当吐之，适宜用瓜蒂散。", annotation: "似桂枝证但头不痛项不强，非表证。胸中痞硬、气上冲不得息为痰实壅阻胸膈。寸脉微浮为病在上焦。因势利导，瓜蒂散涌吐。" },
  { id: "SH-167", chapter: "辨太阳病脉证并治下", original: "病胁下素有痞，连在脐旁，痛引少腹，入阴筋者，此名脏结，死。", translation: "病胁下素有痞块，连在脐旁，疼痛牵引少腹，引入阴筋的，这名叫脏结，死。", annotation: "素有痞块连脐旁为阴寒凝结日久。痛引少腹入阴筋为阴寒至极，阳气竭绝。脏结死证。" },
  { id: "SH-168", chapter: "辨太阳病脉证并治下", original: "伤寒，若吐若下后，七八日不解，热结在里，表里俱热，时时恶风，大渴，舌上干燥而烦，欲饮水数升者，白虎加人参汤主之。", translation: "伤寒，或吐或下后，七八天不解，热结在里，表里都热，时时怕风，大渴，舌上干燥而烦，想要饮水数升的，用白虎加人参汤主治。", annotation: "吐下后热结于里。表里俱热为热盛。时时恶风为热甚汗多、表气不固。大渴舌燥欲饮水数升为热盛津伤。白虎加人参汤清热益气生津。" },
  { id: "SH-169", chapter: "辨太阳病脉证并治下", original: "伤寒，无大热，口燥渴，心烦，背微恶寒者，白虎加人参汤主之。", translation: "伤寒，无大热，口燥口渴，心烦，背部微恶寒的，用白虎加人参汤主治。", annotation: "无大热为热结于里、表无大热。口燥渴、心烦为内热盛。背微恶寒为热甚汗出阳虚。白虎加人参汤清热生津。" },
  { id: "SH-170", chapter: "辨太阳病脉证并治下", original: "伤寒，脉浮，发热无汗，其表不解，不可与白虎汤。渴欲饮水，无表证者，白虎加人参汤主之。", translation: "伤寒，脉象浮，发热无汗，表邪未解，不可给予白虎汤。口渴想要喝水，没有表证的，用白虎加人参汤主治。", annotation: "脉浮发热无汗为表寒未解，白虎汤寒凉冰伏邪气。渴欲饮水无表证为里热津伤，可与白虎加人参汤。" },
  { id: "SH-171", chapter: "辨太阳病脉证并治下", original: "太阳少阳并病，心下硬，颈项强而眩者，当刺大椎、肺俞、肝俞，慎勿下之。", translation: "太阳少阳并病，心下硬，颈项僵硬而目眩的，应当针刺大椎、肺俞、肝俞，切不可攻下。", annotation: "心下硬为少阳。颈项强为太阳。眩为少阳。宜刺不宜下。" },
  { id: "SH-172", chapter: "辨太阳病脉证并治下", original: "太阳与少阳合病，自下利者，与黄芩汤；若呕者，黄芩加半夏生姜汤主之。", translation: "太阳与少阳合病，自行下利的，给予黄芩汤；如果呕吐的，用黄芩加半夏生姜汤主治。", annotation: "二阳合病，邪热下迫大肠自下利。黄芩汤（黄芩、芍药、甘草、大枣）清热止利。呕加半夏生姜降逆。" },
  { id: "SH-173", chapter: "辨太阳病脉证并治下", original: "伤寒，胸中有热，胃中有邪气，腹中痛，欲呕吐者，黄连汤主之。", translation: "伤寒，胸中有热，胃中有寒邪，腹中疼痛，想要呕吐的，用黄连汤主治。", annotation: "上热下寒。胸中有热欲呕，胃中有寒腹痛。黄连汤（黄连、甘草、干姜、桂枝、人参、半夏、大枣）清上温下、和胃降逆。" },
  { id: "SH-174", chapter: "辨太阳病脉证并治下", original: "伤寒八九日，风湿相搏，身体疼烦，不能自转侧，不呕不渴，脉浮虚而涩者，桂枝附子汤主之。若其人大便硬，小便自利者，去桂加白术汤主之。", translation: "伤寒八九天，风湿相互搏结，身体疼痛烦扰，不能自行转侧，不呕不渴，脉象浮虚而涩的，用桂枝附子汤主治。如果病人大便硬，小便自利的，用去桂加白术汤主治。", annotation: "风湿表阳虚。身体疼烦不能转侧为风湿阻滞经脉。不呕不渴无里证。脉浮虚而涩为表阳虚兼湿。桂枝附子汤温经祛风除湿。大便硬小便自利为湿去津伤，去桂加白术健脾燥湿。" },
  { id: "SH-175", chapter: "辨太阳病脉证并治下", original: "风湿相搏，骨节疼烦，掣痛不得屈伸，近之则痛剧，汗出短气，小便不利，恶风不欲去衣，或身微肿者，甘草附子汤主之。", translation: "风湿相互搏结，骨节疼痛烦扰，抽痛不得屈伸，靠近就疼痛加剧，汗出短气，小便不利，怕风不想脱衣，或身体微肿的，用甘草附子汤主治。", annotation: "风湿表里阳虚。骨节疼烦掣痛为风湿入关节。汗出短气、恶风不欲去衣为表阳虚。小便不利、身微肿为湿阻三焦。甘草附子汤温阳散寒、祛风除湿。" },
  { id: "SH-176", chapter: "辨太阳病脉证并治下", original: "伤寒脉浮滑，此以表有热，里有寒，白虎汤主之。", translation: "伤寒脉象浮滑，这是表有热，里有寒（此有争议，当以方测证，实为表里俱热），用白虎汤主治。", annotation: "脉浮滑为热盛。白虎汤为清热重剂，当为表里俱热之证。'里有寒'疑为传写之误。" },
  { id: "SH-177", chapter: "辨太阳病脉证并治下", original: "伤寒脉结代，心动悸，炙甘草汤主之。", translation: "伤寒脉象结代，心中悸动的，用炙甘草汤主治。", annotation: "脉结代为心气心阴不足，脉气不续。心动悸为心失所养。炙甘草汤（炙甘草、生姜、人参、生地黄、桂枝、阿胶、麦门冬、麻仁、大枣）益气滋阴、通阳复脉。" },
  { id: "SH-178", chapter: "辨太阳病脉证并治下", original: "脉按之来缓，时一止复来者，名曰结。又脉来动而中止，更来小数，中有还者反动，名曰结阴也。脉来动而中止，不能自还，因而复动者，名曰代阴也。得此脉者必难治。", translation: "脉象按之来时缓慢，时有一止又来的，名叫结。又脉来时动而中止，再来时稍快，中有停顿又动的，名叫结阴。脉来时动而中止，不能自行恢复，因而又动的，名叫代阴。见到这种脉象必定难治。", annotation: "结脉为缓而时止，病较轻。代脉为动而中止不能自还，病较重。得此脉者正气大虚，为难治。" },
  { id: "SH-179", chapter: "辨阳明病脉证并治", original: "问曰：病有太阳阳明，有正阳阳明，有少阳阳明，何谓也？答曰：太阳阳明者，脾约是也；正阳阳明者，胃家实是也；少阳阳明者，发汗、利小便已，胃中燥烦实，大便难是也。", translation: "问道：病有太阳阳明，有正阳阳明，有少阳阳明，怎么解释？回答说：太阳阳明，就是脾约；正阳阳明，就是胃家实；少阳阳明，就是发汗、利小便后，胃中干燥烦实，大便困难。", annotation: "阳明病有三因：太阳阳明为太阳病发汗不彻或误治转属阳明，脾津被约；正阳阳明为阳明本身热盛成实；少阳阳明为少阳病误汗利小便津伤胃燥。" },
  { id: "SH-180", chapter: "辨阳明病脉证并治", original: "阳明之为病，胃家实是也。", translation: "阳明病的表现，就是胃家（胃肠）实热。", annotation: "此为阳明病提纲。胃家包括胃与大肠。实指邪气盛实。胃家实是阳明病的基本病机。" },
  { id: "SH-181", chapter: "辨阳明病脉证并治", original: "问曰：何缘得阳明病？答曰：太阳病，若发汗，若下，若利小便，此亡津液，胃中干燥，因转属阳明。不更衣，内实，大便难者，此名阳明也。", translation: "问道：怎么得的阳明病？回答说：太阳病，或发汗，或攻下，或利小便，这样耗伤津液，胃中干燥，因而转属阳明。不大便，内实，大便困难的，这名叫阳明病。", annotation: "太阳病误治伤津转属阳明。不更衣（不大便）、内实、大便难为阳明实证。" },
  { id: "SH-182", chapter: "辨阳明病脉证并治", original: "问曰：阳明病外证云何？答曰：身热，汗自出，不恶寒，反恶热也。", translation: "问道：阳明病的外在症状如何？回答说：身体发热，自汗出，不恶寒，反而怕热。", annotation: "阳明外证四大症：身热、自汗、不恶寒、反恶热。与太阳表证鉴别要点。" },
  { id: "SH-183", chapter: "辨阳明病脉证并治", original: "问曰：病有得之一日，不发热而恶寒者，何也？答曰：虽得之一日，恶寒将自罢，即自汗出而恶热也。", translation: "问道：病有得病第一天，不发热而怕冷的，为什么？回答说：虽然得病一天，怕冷将会自行停止，就自汗出而怕热。", annotation: "阳明初起可有短暂恶寒，但必自罢，随即汗出恶热。与太阳病恶寒持续不解不同。" },
  { id: "SH-184", chapter: "辨阳明病脉证并治", original: "问曰：恶寒何故自罢？答曰：阳明居中，主土也，万物所归，无所复传，始虽恶寒，二日自止，此为阳明病也。", translation: "问道：怕冷为什么自行停止？回答说：阳明位居中央，属土，是万物所归的地方，邪入阳明不再传变，开始虽然怕冷，二天就自止，这是阳明病。", annotation: "阳明为土居中，万物所归，邪入阳明一般不再传经。恶寒短暂自止为阳明病特点。" },
  { id: "SH-185", chapter: "辨阳明病脉证并治", original: "本太阳初得病时，发其汗，汗先出不彻，因转属阳明也。伤寒发热无汗，呕不能食，而反汗出濈濈然者，是转属阳明也。", translation: "本来太阳初得病时，发汗，汗先出不透彻，因而转属阳明。伤寒发热无汗，呕吐不能食，反而汗出不断的，是转属阳明。", annotation: "太阳病发汗不彻，邪不外达内传阳明。呕不能食、汗出濈濈然为阳明热盛迫汗。" },
  { id: "SH-186", chapter: "辨阳明病脉证并治", original: "伤寒三日，阳明脉大。", translation: "伤寒三天，阳明脉大。", annotation: "阳明为多气多血之经，邪入阳明正盛邪实，脉大有力。" },
  { id: "SH-187", chapter: "辨阳明病脉证并治", original: "伤寒脉浮而缓，手足自温者，是为系在太阴。太阴者，身当发黄，若小便自利者，不能发黄。至七八日，大便硬者，为阳明病也。", translation: "伤寒脉象浮而缓，手足温暖的，这是系在太阴。太阴病，身体应当发黄，如果小便自利的，不能发黄。到七八天，大便硬的，是阳明病。", annotation: "脉浮缓手足温为太阴湿盛。太阴湿郁当发黄，小便利湿有去路不发黄。七八日大便硬为湿从燥化，转属阳明。" },
  { id: "SH-188", chapter: "辨阳明病脉证并治", original: "伤寒转系阳明者，其人濈濈然微汗出也。", translation: "伤寒转属阳明的，病人微微汗出不断。", annotation: "濈濈然汗出为阳明热盛迫津外泄之征。" },
  { id: "SH-189", chapter: "辨阳明病脉证并治", original: "阳明中风，口苦咽干，腹满微喘，发热恶寒，脉浮而紧，若下之，则腹满小便难也。", translation: "阳明中风，口苦咽干，腹部胀满微喘，发热恶寒，脉象浮而紧，如果攻下，就会腹部胀满小便困难。", annotation: "阳明病兼太阳少阳。口苦咽干为少阳，腹满微喘为阳明，发热恶寒脉浮紧为太阳。三阳合病当先解表，误下则里气更伤。" },
  { id: "SH-190", chapter: "辨阳明病脉证并治", original: "阳明病，若能食，名中风；不能食，名中寒。", translation: "阳明病，如果能食，名叫中风；不能食，名叫中寒。", annotation: "阳明中风为阳邪，能食说明胃气尚强。阳明中寒为阴邪，不能食说明胃阳虚寒。" },
  { id: "SH-191", chapter: "辨阳明病脉证并治", original: "阳明病，若中寒者，不能食，小便不利，手足濈然汗出，此欲作固瘕，必大便初硬后溏。所以然者，以胃中冷，水谷不别故也。", translation: "阳明病，如果中寒的，不能食，小便不利，手足不断出汗，这将要形成固瘕，必定大便初硬后溏。之所以这样，是因为胃中寒冷，水谷不化的缘故。", annotation: "中寒不能食为胃阳虚。小便不利、手足汗出为寒饮内停。固瘕为寒结。初硬后溏为胃冷水谷不别。" },
  { id: "SH-192", chapter: "辨阳明病脉证并治", original: "阳明病，初欲食，小便反不利，大便自调，其人骨节疼，翕翕如有热状，奄然发狂，濈然汗出而解者，此水不胜谷气，与汗共并，脉紧则愈。", translation: "阳明病，初想食，小便反而不利，大便正常，病人骨节疼痛，翕翕如有发热的样子，忽然发狂，汗出不断而病解的，这是水湿不胜谷气，与汗共同排出，脉紧就痊愈。", annotation: "初欲食、大便自调为胃气尚强。小便不利、骨节疼为湿痹。奄然发狂濈然汗出为正胜邪去。水湿从汗出解。脉紧为邪去正复。" },
  { id: "SH-193", chapter: "辨阳明病脉证并治", original: "阳明病，欲解时，从申至戌上。", translation: "阳明病，欲解时间，从申时到戌时。", annotation: "申酉戌为阳明经气旺盛之时，正盛邪退病欲解。" },
  { id: "SH-194", chapter: "辨阳明病脉证并治", original: "阳明病，不能食，攻其热必哕。所以然者，胃中虚冷故也。以其人本虚，攻其热必哕。", translation: "阳明病，不能食，攻其热必定呃逆。之所以这样，是因为胃中虚冷的缘故。因为病人本虚，攻其热必呃逆。", annotation: "阳明中寒不能食为胃虚冷，非实热。误攻其热则胃气更伤，致哕。" },
  { id: "SH-195", chapter: "辨阳明病脉证并治", original: "阳明病，脉迟，食难用饱，饱则微烦头眩，必小便难，此欲作谷瘅。虽下之，腹满如故。所以然者，脉迟故也。", translation: "阳明病，脉象迟，食难用饱，饱则微烦头眩，必定小便困难，这将要形成谷瘅。即使攻下，腹满仍然如故。之所以这样，是因为脉迟的缘故。", annotation: "脉迟为寒湿。食饱则微烦头眩为湿郁。小便难为湿无去路。谷瘅为寒湿发黄。下之寒湿更甚，腹满如故。" },
  { id: "SH-196", chapter: "辨阳明病脉证并治", original: "阳明病，法多汗，反无汗，其身如虫行皮中状者，此以久虚故也。", translation: "阳明病，按理多汗，反而无汗，身体像虫在皮肤中爬行的样子，这是因为久虚的缘故。", annotation: "阳明法多汗。无汗身痒如虫行为气虚津少，不能化汗。" },
  { id: "SH-197", chapter: "辨阳明病脉证并治", original: "阳明病，反无汗，而小便利，二三日呕而咳，手足厥者，必苦头痛。若不咳不呕，手足不厥者，头不痛。", translation: "阳明病，反而无汗，而小便通利，二三天呕吐而咳嗽，手足厥冷的，必定苦于头痛。如果不咳不呕，手足不厥冷的，头不痛。", annotation: "无汗小便利呕咳手足厥为阳虚阴盛。阴寒上逆头痛。不呕不咳手足不厥则阴寒不上逆，头不痛。" },
  { id: "SH-198", chapter: "辨阳明病脉证并治", original: "阳明病，但头眩，不恶寒，故能食而咳，其人咽必痛。若不咳者，咽不痛。", translation: "阳明病，只有头眩，不恶寒，所以能食而咳嗽，病人咽喉必定疼痛。如果不咳的，咽喉不痛。", annotation: "头眩不恶寒能食为阳明中风热盛。咳为热邪上逆。咽为热邪所灼故痛。不咳则热不上逆，咽不痛。" },
  { id: "SH-199", chapter: "辨阳明病脉证并治", original: "阳明病，无汗，小便不利，心中懊憹者，身必发黄。", translation: "阳明病，无汗，小便不利，心中懊憹的，身体必定发黄。", annotation: "无汗则热不外达，小便不利则湿不下泄，湿热郁蒸心中懊憹，身必发黄。" },
  { id: "SH-200", chapter: "辨阳明病脉证并治", original: "阳明病，被火，额上微汗出，而小便不利者，必发黄。", translation: "阳明病，被火攻，额上微微出汗，而小便不利的，必定发黄。", annotation: "阳明病误火，热更甚。额上汗出、小便不利为湿热郁蒸不解。" },
  { id: "SH-201", chapter: "辨阳明病脉证并治", original: "阳明病，脉浮而紧者，必潮热，发作有时。但浮者，必盗汗出。", translation: "阳明病，脉象浮而紧的，必定潮热，发作有时。只脉浮的，必定盗汗出。", annotation: "脉浮紧为邪盛实，潮热为阳明典型热型。脉浮但盗汗出为热迫津液外泄。" },
  { id: "SH-202", chapter: "辨阳明病脉证并治", original: "阳明病，口燥，但欲漱水，不欲咽者，此必衄。", translation: "阳明病，口燥，只想漱口，不想咽下的，这必定鼻出血。", annotation: "口燥但欲漱水不欲咽为热在血分。热迫血妄行必衄。" },
  { id: "SH-203", chapter: "辨阳明病脉证并治", original: "阳明病，本自汗出，医更重发汗，病已差，尚微烦不了了者，此必大便硬故也。以亡津液，胃中干燥，故令大便硬。当问其小便日几行，若本小便日三四行，今日再行，故知大便不久出。今为小便数少，以津液当还入胃中，故知不久必大便也。", translation: "阳明病，本来自汗出，医生又重发汗，病已愈，仍微烦不爽快的，这必定是大便硬的缘故。因为津液耗伤，胃中干燥，所以使大便硬。应当问其小便一天几次，如果本来小便一天三四次，今天只两次，所以知道大便不久就出。现在因为小便次数减少，津液应当还入胃中，所以知道不久必大便。", annotation: "汗后津伤便硬。观小便多少可测津液情况。小便次数减少说明津液还入胃中，肠中津液恢复，不久便通。" },
  { id: "SH-204", chapter: "辨阳明病脉证并治", original: "伤寒呕多，虽有阳明证，不可攻之。", translation: "伤寒呕吐多，虽然有阳明证，不可攻下。", annotation: "呕多为邪气在上或胃气上逆，虽有阳明证不可攻。当先和胃止呕。" },
  { id: "SH-205", chapter: "辨阳明病脉证并治", original: "阳明病，心下硬满者，不可攻之。攻之，利遂不止者死，利止者愈。", translation: "阳明病，心下硬满的，不可攻下。攻下后，下利不止的死，利止的愈。", annotation: "心下硬满为病位在胃脘，非阳明腹满燥屎。误攻伤正，利不止死。利止正气犹存可愈。" },
  { id: "SH-206", chapter: "辨阳明病脉证并治", original: "阳明病，面合色赤，不可攻之。必发热，色黄者，小便不利也。", translation: "阳明病，满面通红的，不可攻下。攻下后必发热，面色黄的，小便不利。", annotation: "面合色赤为佛郁在表未全入里。误攻则邪陷，湿热郁蒸发黄小便不利。" },
  { id: "SH-207", chapter: "辨阳明病脉证并治", original: "阳明病，不吐不下，心烦者，可与调胃承气汤。", translation: "阳明病，不吐不下，心烦的，可以给予调胃承气汤。", annotation: "不吐不下非少阳太阴。心烦为阳明热扰。调胃承气汤缓下热结。" },
  { id: "SH-208", chapter: "辨阳明病脉证并治", original: "阳明病，脉迟，虽汗出不恶寒者，其身必重，短气，腹满而喘，有潮热者，此外欲解，可攻里也。手足濈然汗出者，此大便已硬也，大承气汤主之。若汗多，微发热恶寒者，外未解也，其热不潮，未可与承气汤。若腹大满不通者，可与小承气汤，微和胃气，勿令至大泄下。", translation: "阳明病，脉象迟，虽然汗出不恶寒的，身体必定沉重，短气，腹满而喘，有潮热的，这是表邪欲解，可以攻里。手足不断出汗的，这是大便已经硬了，用大承气汤主治。如果汗多，微发热恶寒的，表邪未解，其热不潮，不可给予承气汤。如果腹大满不通的，可以给予小承气汤，微和胃气，不要让它大泻下。", annotation: "此条辨阳明腑实攻下标准。脉迟、汗出不恶寒、身重短气腹满而喘为阳明里实。潮热、手足濈然汗出为燥屎成，可大承气汤。汗多微恶寒外未解不可攻。腹大满不通用小承气汤微和。" },
  { id: "SH-209", chapter: "辨阳明病脉证并治", original: "阳明病，潮热，大便微硬者，可与大承气汤，不硬者，不可与之。若不大便六七日，恐有燥屎，欲知之法，少与小承气汤，汤入腹中，转失气者，此有燥屎也，乃可攻之。若不转失气者，此但初头硬，后必溏，不可攻之，攻之必胀满不能食也。欲饮水者，与水则哕。其后发热者，必大便复硬而少也，以小承气汤和之。不转失气者，慎不可攻也。", translation: "阳明病，潮热，大便微硬的，可以给予大承气汤，不硬的，不可给予。如果不大便六七天，恐怕有燥屎，想知道的方法，少量给予小承气汤，药入腹中，转矢气（放屁）的，这是有燥屎，才可攻下。如果不转矢气的，这只是初头硬，后必溏，不可攻下，攻下必定胀满不能食。想喝水的，给予水就会呃逆。以后发热的，必定大便又硬而少，用小承气汤调和。不转矢气的，切不可攻下。", annotation: "此条示人以小承气汤试探燥屎之法。转矢气为有燥屎，可攻。不转矢气为无燥屎，不可攻。误攻变证。" },
  { id: "SH-210", chapter: "辨阳明病脉证并治", original: "夫实则谵语，虚则郑声。郑声者，重语也。直视谵语，喘满者死，下利者亦死。", translation: "实证就会说胡话（谵语），虚证就会郑声。郑声就是说话重复。直视谵语，气喘胀满的死，下利的也死。", annotation: "谵语为邪实扰神，声高气粗。郑声为正虚神散，语低重复。直视谵语为热极阴竭。喘满为肺气脱，下利为中气脱，皆死。" },
  { id: "SH-211", chapter: "辨阳明病脉证并治", original: "发汗多，若重发汗者，亡其阳，谵语，脉短者死，脉自和者不死。", translation: "发汗多，或者重复发汗的，亡其阳气，说胡话，脉短的死，脉自和的不死。", annotation: "过汗亡阳。谵语脉短为气血津液皆竭。脉自和为正气未脱。" },
  { id: "SH-212", chapter: "辨阳明病脉证并治", original: "伤寒，若吐若下后，不解，不大便五六日，上至十余日，日晡所发潮热，不恶寒，独语如见鬼状。若剧者，发则不识人，循衣摸床，惕而不安，微喘直视，脉弦者生，涩者死。微者，但发热谵语者，大承气汤主之。若一服利，则止后服。", translation: "伤寒，或吐或下后，病不解，不大便五六天，甚至十多天，午后发潮热，不恶寒，独自说话像见鬼的样子。如果严重的，发作时就不认人，循衣摸床，惊惕不安，微喘直视，脉弦的生，脉涩的死。轻的，只发热说胡话的，用大承气汤主治。如果一服就通利，就停后服。", annotation: "吐下后热结阳明。不大便、潮热、不恶寒、谵语为阳明腑实重证。剧者不识人、循衣摸床、微喘直视为热极阴竭。脉弦为阴未尽竭可生，脉涩为阴血已竭死。" },
  { id: "SH-213", chapter: "辨阳明病脉证并治", original: "阳明病，其人多汗，以津液外出，胃中燥，大便必硬，硬则谵语，小承气汤主之。若一服谵语止者，更莫复服。", translation: "阳明病，病人多汗，因为津液外出，胃中干燥，大便必定硬，硬就说胡话，用小承气汤主治。如果一服谵语止的，不要再服。", annotation: "多汗津伤便硬谵语。小承气汤泻下热结。谵语止即止后服，免伤正气。" },
  { id: "SH-214", chapter: "辨阳明病脉证并治", original: "阳明病，谵语，发潮热，脉滑而疾者，小承气汤主之。因与承气汤一升，腹中转气者，更服一升。若不转气者，勿更与之。明日又不大便，脉反微涩者，里虚也，为难治，不可更与承气汤也。", translation: "阳明病，说胡话，发潮热，脉象滑而疾的，用小承气汤主治。于是给予承气汤一升，腹中转气的，再服一升。如果不转气的，不要再给。明天又不大便，脉反微涩的，是里虚，为难治，不可再给承气汤。", annotation: "谵语潮热脉滑疾为阳明腑实，小承气汤主之。转气再服，不转气勿服。明日不大便脉反微涩为里虚，难治。" },
  { id: "SH-215", chapter: "辨阳明病脉证并治", original: "阳明病，谵语，有潮热，反不能食者，胃中必有燥屎五六枚也。若能食者，但硬耳。宜大承气汤下之。", translation: "阳明病，说胡话，有潮热，反而不能食的，胃中必定有燥屎五六枚。如果能食的，只是大便硬而已。适宜用大承气汤攻下。", annotation: "谵语潮热为阳明里实。不能食为燥屎阻塞胃气不降。能食为大便初硬或未完全阻塞。大承气汤下之。" },
  { id: "SH-216", chapter: "辨阳明病脉证并治", original: "阳明病，下血谵语者，此为热入血室，但头汗出者，刺期门，随其实而泻之，濈然汗出则愈。", translation: "阳明病，下血说胡话的，这是热入血室，只有头部出汗的，针刺期门，随其实而泻之，汗出不断就愈。", annotation: "阳明热入血室。下血为热迫血行。刺期门泻肝，使热随血去。濈然汗出愈。" },
  { id: "SH-217", chapter: "辨阳明病脉证并治", original: "汗出谵语者，以有燥屎在胃中，此为风也。须下者，过经乃可下之。下之若早，语言必乱，以表虚里实故也。下之愈，宜大承气汤。", translation: "汗出说胡话的，是因为有燥屎在胃中，这是风邪。必须攻下的，过经才可攻下。攻下太早，语言必乱，因为表虚里实的缘故。攻下就愈，适宜用大承气汤。", annotation: "汗出为风邪表虚，谵语为燥屎里实。需过经（表解）乃可下。下早表邪内陷更甚。" },
  { id: "SH-218", chapter: "辨阳明病脉证并治", original: "伤寒四五日，脉沉而喘满，沉为在里，而反发其汗，津液越出，大便为难，表虚里实，久则谵语。", translation: "伤寒四五天，脉象沉而气喘胀满，沉是在里，反而发汗，津液外泄，大便困难，表虚里实，日久就说胡话。", annotation: "脉沉喘满为里实证。误汗津伤便硬，久则谵语。" },
  { id: "SH-219", chapter: "辨阳明病脉证并治", original: "三阳合病，腹满身重，难以转侧，口不仁，面垢，谵语遗尿。发汗则谵语，下之则额上生汗，手足逆冷。若自汗出者，白虎汤主之。", translation: "三阳合病，腹满身重，难以转侧，口不知味，面垢，说胡话遗尿。发汗就会更谵语，攻下就会额上出汗，手足逆冷。如果自汗出的，用白虎汤主治。", annotation: "三阳合病以阳明热盛为主。腹满身重难以转侧、口不仁、面垢、谵语、遗尿为阳明热盛。发汗更伤津致谵语。下之额上汗出手足冷为阳气外脱。自汗出为阳明热迫，白虎汤清热。" },
  { id: "SH-220", chapter: "辨阳明病脉证并治", original: "二阳并病，太阳证罢，但发潮热，手足漐漐汗出，大便难而谵语者，下之则愈，宜大承气汤。", translation: "二阳并病，太阳证罢，只有发潮热，手足微微出汗，大便难而说胡话的，攻下就愈，适宜用大承气汤。", annotation: "太阳证罢为表已解。潮热、手足汗出、大便难谵语为阳明腑实。大承气汤下之。" },
  { id: "SH-221", chapter: "辨阳明病脉证并治", original: "阳明病，脉浮而紧，咽燥口苦，腹满而喘，发热汗出，不恶寒反恶热，身重。若发汗则躁，心愦愦反谵语。若加温针，必怵惕烦躁不得眠。若下之，则胃中空虚，客气动膈，心中懊憹，舌上胎者，栀子豉汤主之。", translation: "阳明病，脉象浮而紧，咽燥口苦，腹满而喘，发热汗出，不恶寒反恶热，身重。如果发汗就会烦躁，心中昏乱反而说胡话。如果加用温针，必定惊惕烦躁不得眠。如果攻下，就会胃中虚空，邪气扰动胸膈，心中懊憹，舌上有苔的，用栀子豉汤主治。", annotation: "阳明经热证误治变证。发汗、温针助热伤津。误下后虚热留扰胸膈，栀子豉汤主之。" },
  { id: "SH-222", chapter: "辨阳明病脉证并治", original: "若渴欲饮水，口干舌燥者，白虎加人参汤主之。", translation: "如果渴欲饮水，口干舌燥的，用白虎加人参汤主治。", annotation: "此为阳明热盛津伤。白虎汤清热，人参益气生津。" },
  { id: "SH-223", chapter: "辨阳明病脉证并治", original: "若脉浮，发热，渴欲饮水，小便不利者，猪苓汤主之。", translation: "如果脉象浮，发热，渴欲饮水，小便不利的，用猪苓汤主治。", annotation: "此为阳明热盛兼水热互结。脉浮发热为热，渴小便不利为水热不化津。猪苓汤（猪苓、茯苓、泽泻、阿胶、滑石）滋阴清热利水。" },
  { id: "SH-224", chapter: "辨阳明病脉证并治", original: "阳明病，汗出多而渴者，不可与猪苓汤。以汗多胃中燥，猪苓汤复利其小便故也。", translation: "阳明病，汗出多而口渴的，不可给予猪苓汤。因为汗多胃中燥，猪苓汤又利其小便的缘故。", annotation: "汗多口渴为纯热津伤，宜白虎加人参汤清热生津。猪苓汤利水更伤津液。" },
  { id: "SH-225", chapter: "辨阳明病脉证并治", original: "脉浮而迟，表热里寒，下利清谷者，四逆汤主之。", translation: "脉象浮而迟，表热里寒，下利完谷不化的，用四逆汤主治。", annotation: "脉浮为表热，脉迟为里寒。下利清谷为里虚寒甚。此为真寒假热。四逆汤回阳救逆。" },
  { id: "SH-226", chapter: "辨阳明病脉证并治", original: "若胃中虚冷，不能食者，饮水则哕。", translation: "如果胃中虚冷，不能食的，饮水就会呃逆。", annotation: "胃阳虚寒，饮水则水寒相搏，胃气上逆哕。" },
  { id: "SH-227", chapter: "辨阳明病脉证并治", original: "脉浮发热，口干鼻燥，能食者则衄。", translation: "脉象浮发热，口干鼻燥，能食的就会鼻出血。", annotation: "脉浮发热口干鼻燥为热盛。能食为胃气强，热盛迫血上溢则衄。" },
  { id: "SH-228", chapter: "辨阳明病脉证并治", original: "阳明病，下之，其外有热，手足温，不结胸，心中懊憹，饥不能食，但头汗出者，栀子豉汤主之。", translation: "阳明病，攻下后，外表有热，手足温暖，不结胸，心中懊憹，饥不能食，只有头部出汗的，用栀子豉汤主治。", annotation: "下后余热留扰胸膈。外有热手足温、心中懊憹、饥不能食、头汗出为虚热之征。栀子豉汤清宣郁热。" },
  { id: "SH-229", chapter: "辨阳明病脉证并治", original: "阳明病，发潮热，大便溏，小便自可，胸胁满不去者，与小柴胡汤。", translation: "阳明病，发潮热，大便溏，小便正常，胸胁胀满不去的，给予小柴胡汤。", annotation: "潮热似阳明腑实，但大便溏小便自可非燥屎。胸胁满为少阳证不去。少阳阳明并病以少阳为主，小柴胡汤和解。" },
  { id: "SH-230", chapter: "辨阳明病脉证并治", original: "阳明病，胁下硬满，不大便而呕，舌上白胎者，可与小柴胡汤，上焦得通，津液得下，胃气因和，身濈然汗出而解。", translation: "阳明病，胁下硬满，不大便而呕吐，舌上白苔的，可以给予小柴胡汤，上焦得通，津液得下，胃气因而调和，身体汗出不断而解。", annotation: "胁下硬满、呕、苔白为少阳柴胡证。不大便似阳明实为枢机不利津液不下。小柴胡汤和解少阳，枢机转则津液下胃气和汗出而解。" },
  { id: "SH-231", chapter: "辨阳明病脉证并治", original: "阳明中风，脉弦浮大而短气，腹都满，胁下及心痛，久按之气不通，鼻干，不得汗，嗜卧，一身及目悉黄，小便难，有潮热，时时哕，耳前后肿，刺之小差。外不解，病过十日，脉续浮者，与小柴胡汤。", translation: "阳明中风，脉象弦浮大而短气，腹部都满，胁下及心痛，久按之气不通，鼻干，不得出汗，嗜卧，全身及目都黄，小便难，有潮热，时时呃逆，耳前后肿，针刺之稍愈。表证不解，病过十天，脉续浮的，给予小柴胡汤。", annotation: "三阳合病。脉弦（少阳）、浮（太阳）、大（阳明）。腹满鼻干潮热为阳明，胁痛耳前后肿为少阳，不得汗为太阳。黄疸。病过十日脉续浮为邪犹在表，小柴胡汤和解。" },
  { id: "SH-232", chapter: "辨阳明病脉证并治", original: "脉但浮，无余证者，与麻黄汤。若不尿，腹满加哕者，不治。", translation: "脉只浮，无其他证的，给予麻黄汤。如果不尿，腹满加呃逆的，不治。", annotation: "脉但浮无余证为太阳表实，麻黄汤发汗。不尿、腹满、哕为三焦俱绝，不治。" },
  { id: "SH-233", chapter: "辨阳明病脉证并治", original: "阳明病，自汗出，若发汗，小便自利者，此为津液内竭，虽硬不可攻下之，当须自欲大便，宜蜜煎导而通之。若土瓜根及大猪胆汁，皆可为导。", translation: "阳明病，自汗出，如果发汗，小便自利的，这是津液内竭，虽大便硬不可攻下，应当等待自欲大便，适宜用蜜煎导而通之。如果土瓜根及大猪胆汁，都可以导便。", annotation: "自汗小便自利为津伤便硬，非实热燥屎。不可攻下。蜜煎导、土瓜根、猪胆汁皆外用导便。" },
  { id: "SH-234", chapter: "辨阳明病脉证并治", original: "阳明病，脉迟，汗出多，微恶寒者，表未解也，可发汗，宜桂枝汤。", translation: "阳明病，脉象迟，汗出多，微恶寒的，表邪未解，可以发汗，适宜用桂枝汤。", annotation: "阳明病微恶寒为表未解。汗出多为太阳中风。桂枝汤解肌发表。" },
  { id: "SH-235", chapter: "辨阳明病脉证并治", original: "阳明病，脉浮，无汗而喘者，发汗则愈，宜麻黄汤。", translation: "阳明病，脉象浮，无汗而喘的，发汗就愈，适宜用麻黄汤。", annotation: "脉浮无汗而喘为太阳伤寒表实。虽有阳明病亦当先解表。" },
  { id: "SH-236", chapter: "辨阳明病脉证并治", original: "阳明病，发热汗出者，此为热越，不能发黄也。但头汗出，身无汗，剂颈而还，小便不利，渴引水浆者，此为瘀热在里，身必发黄，茵陈蒿汤主之。", translation: "阳明病，发热汗出的，这是热向外发，不能发黄。只有头部出汗，身无汗，到颈部而止，小便不利，渴欲饮水的，这是瘀热在里，身体必发黄，用茵陈蒿汤主治。", annotation: "发热汗出为热随汗泄不发黄。头汗出、小便不利、渴为湿热郁蒸发黄。茵陈蒿汤（茵陈、栀子、大黄）清热利湿退黄。" },
  { id: "SH-237", chapter: "辨阳明病脉证并治", original: "阳明证，其人喜忘者，必有畜血。所以然者，本有久瘀血，故令喜忘，屎虽硬，大便反易，其色必黑者，宜抵当汤下之。", translation: "阳明证，病人健忘的，必有蓄血。之所以这样，本来有久瘀血，所以使人健忘，屎虽硬，大便反而易解，其色必定黑，适宜用抵当汤攻下。", annotation: "阳明蓄血证。久瘀血致健忘。便硬反易色黑为瘀血与便相混。抵当汤破血逐瘀。" },
  { id: "SH-238", chapter: "辨阳明病脉证并治", original: "阳明病，下之，心中懊憹而烦，胃中有燥屎者，可攻。腹微满，初头硬，后必溏，不可攻之。若有燥屎者，宜大承气汤。", translation: "阳明病，攻下后，心中懊憹而烦，胃中有燥屎的，可以攻。腹部微满，初头硬，后必溏，不可攻下。如果有燥屎的，适宜用大承气汤。", annotation: "下后心中懊憹而烦，有燥屎为实热未尽，可再攻。腹微满初硬后溏为无燥屎不可攻。" },
  { id: "SH-239", chapter: "辨阳明病脉证并治", original: "病人不大便五六日，绕脐痛，烦躁，发作有时者，此有燥屎也，故使不大便也。", translation: "病人不大便五六天，绕脐疼痛，烦躁，发作有时的，这是有燥屎，所以使不大便。", annotation: "绕脐痛、烦躁发作有时为燥屎阻塞之征。" },
  { id: "SH-240", chapter: "辨阳明病脉证并治", original: "病人烦热，汗出则解，又如疟状，日晡所发热者，属阳明也。脉实者，宜下之；脉浮虚者，宜发汗。下之与大承气汤，发汗宜桂枝汤。", translation: "病人烦热，汗出就解，又如疟疾状，午后发热的，属阳明。脉实的，适宜攻下；脉浮虚的，适宜发汗。攻下给予大承气汤，发汗适宜用桂枝汤。", annotation: "日晡发热属阳明。脉实为阳明腑实，宜大承气汤下之。脉浮虚为表邪未尽，宜桂枝汤发汗。" },
  { id: "SH-241", chapter: "辨阳明病脉证并治", original: "大下后，六七日不大便，烦不解，腹满痛者，此有燥屎也。所以然者，本有宿食故也，宜大承气汤。", translation: "大下后，六七天不大便，烦躁不解，腹满而痛的，这是有燥屎。之所以这样，本来有宿食的缘故，适宜用大承气汤。", annotation: "大下后复不大便烦腹满痛为燥屎未尽。本有宿食为因。再下之。" },
  { id: "SH-242", chapter: "辨阳明病脉证并治", original: "病人小便不利，大便乍难乍易，时有微热，喘冒不能卧者，有燥屎也，宜大承气汤。", translation: "病人小便不利，大便忽难忽易，时有微热，气喘昏冒不能卧的，是有燥屎，适宜用大承气汤。", annotation: "小便不利为津液不化。大便乍难乍易为有燥屎。微热喘冒为热邪上壅。大承气汤下之。" },
  { id: "SH-243", chapter: "辨阳明病脉证并治", original: "食谷欲呕，属阳明也，吴茱萸汤主之。得汤反剧者，属上焦也。", translation: "食谷欲呕，属阳明，用吴茱萸汤主治。得汤反剧的，属上焦。", annotation: "食谷欲呕为阳明胃寒，吴茱萸汤温胃散寒。得汤反剧为上焦有热，非吴茱萸所宜。" },
  { id: "SH-244", chapter: "辨阳明病脉证并治", original: "太阳病，寸缓关浮尺弱，其人发热汗出，复恶寒，不呕，但心下痞者，此以医下之也。如其不下者，病人不恶寒而渴者，此转属阳明也。小便数者，大便必硬，不更衣十日，无所苦也。渴欲饮水，少少与之，但以法救之。渴者，宜五苓散。", translation: "太阳病，寸缓关浮尺弱，病人发热汗出，又怕冷，不呕，只是心下痞的，这是因为医生攻下的缘故。如果没有攻下，病人不恶寒而口渴的，这是转属阳明。小便次数多的，大便必硬，不大便十天，也没有什么痛苦。渴欲饮水，少量给予，但依法救治。口渴的，适宜用五苓散。", annotation: "太阳病误下致心下痞。未下转属阳明。小便数大便硬十日无所苦为脾约证。渴饮水少少与。渴而小便不利为水停，五苓散。" },
  { id: "SH-245", chapter: "辨阳明病脉证并治", original: "脉阳微而汗出少者，为自和也。汗出多者，为太过。阳脉实，因发其汗，出多者，亦为太过。太过者，为阳绝于里，亡津液，大便因硬也。", translation: "脉阳微而汗出少的，是自和。汗出多的，是太过。阳脉实，因为发汗，出多的，也是太过。太过的，是阳气独盛于里，津液耗伤，大便因而硬。", annotation: "阳微汗少自和。阳实多汗为阳热过盛，津伤便硬。" },
  { id: "SH-246", chapter: "辨阳明病脉证并治", original: "脉浮而芤，浮为阳，芤为阴，浮芤相搏，胃气生热，其阳则绝。", translation: "脉象浮而芤，浮为阳盛，芤为阴虚，浮芤相搏，胃气生热，其阳就独盛。", annotation: "浮芤为阳盛阴虚。胃气热而阴绝。" },
  { id: "SH-247", chapter: "辨阳明病脉证并治", original: "趺阳脉浮而涩，浮则胃气强，涩则小便数，浮涩相搏，大便则硬，其脾为约，麻子仁丸主之。", translation: "趺阳脉浮而涩，浮是胃气强，涩是小便数，浮涩相搏，大便就硬，其脾被约，用麻子仁丸主治。", annotation: "趺阳主胃。浮为胃气强，涩为脾阴不足。小便数大便硬为脾约。麻子仁丸（麻子仁、芍药、枳实、大黄、厚朴、杏仁）润肠泻下。" },
  { id: "SH-248", chapter: "辨阳明病脉证并治", original: "太阳病三日，发汗不解，蒸蒸发热者，属胃也，调胃承气汤主之。", translation: "太阳病三天，发汗不解，蒸蒸发热的，属阳明胃，用调胃承气汤主治。", annotation: "汗后病不解，蒸蒸发热为阳明里热炽盛。调胃承气汤泻热和胃。" },
  { id: "SH-249", chapter: "辨阳明病脉证并治", original: "伤寒吐后，腹胀满者，与调胃承气汤。", translation: "伤寒吐后，腹胀满的，给予调胃承气汤。", annotation: "吐后腹胀满为热结未尽。调胃承气汤泻热除满。" },
  { id: "SH-250", chapter: "辨阳明病脉证并治", original: "太阳病，若吐若下若发汗后，微烦，小便数，大便因硬者，与小承气汤和之愈。", translation: "太阳病，或吐或下或发汗后，微烦，小便数，大便因而硬的，给予小承气汤调和就愈。", annotation: "吐下发汗后津伤热结便硬。小承气汤泻下热结和胃。" },
  { id: "SH-251", chapter: "辨阳明病脉证并治", original: "得病二三日，脉弱，无太阳柴胡证，烦躁，心下硬。至四五日，虽能食，以小承气汤，少少与，微和之，令小安。至六日，与承气汤一升。若不大便六七日，小便少者，虽不受食，但初头硬，后必溏，未定成硬，攻之必溏。须小便利，屎定硬，乃可攻之，宜大承气汤。", translation: "得病二三天，脉弱，无太阳柴胡证，烦躁，心下硬。到四五天，虽能食，用小承气汤少量给予，微和胃气，使稍安。到六天，给予承气汤一升。如果不大便六七天，小便少的，虽不能食，只是初头硬，后必溏，未定成硬，攻下必溏。必须小便利，屎定硬，才可攻下，适宜用大承气汤。", annotation: "脉弱为正气不足。无太阳柴胡证为邪在里。烦躁心下硬为胃热。先小承气汤少少与。小便多少测津液。小便少非实不可攻。小便利屎定硬乃可攻。" },
  { id: "SH-252", chapter: "辨阳明病脉证并治", original: "伤寒六七日，目中不了了，睛不和，无表里证，大便难，身微热者，此为实也，急下之，宜大承气汤。", translation: "伤寒六七天，视物不清，眼睛转动不灵活，无表里证，大便难，身微热的，这是实证，急下之，适宜用大承气汤。", annotation: "目中不了了睛不和为热极阴竭，目失所养。虽无明显表里证，但大便难身微热为实热。急下存阴。" },
  { id: "SH-253", chapter: "辨阳明病脉证并治", original: "阳明病，发热汗多者，急下之，宜大承气汤。", translation: "阳明病，发热汗多的，急下之，适宜用大承气汤。", annotation: "发热汗多为热盛津伤极速。急下存阴。" },
  { id: "SH-254", chapter: "辨阳明病脉证并治", original: "发汗不解，腹满痛者，急下之，宜大承气汤。", translation: "发汗不解，腹满而痛的，急下之，适宜用大承气汤。", annotation: "汗后病不解腹满痛为阳明实热壅盛。急下存阴。" },
  { id: "SH-255", chapter: "辨阳明病脉证并治", original: "腹满不减，减不足言，当下之，宜大承气汤。", translation: "腹满不减，减亦不足言，应当攻下，适宜用大承气汤。", annotation: "腹满持续不减为阳明实。若减不足言为虽减不甚。大承气汤下之。" },
  { id: "SH-256", chapter: "辨阳明病脉证并治", original: "阳明少阳合病，必下利。其脉不负者，为顺也。负者，失也，互相克贼，名为负也。脉滑而数者，有宿食也，当下之，宜大承气汤。", translation: "阳明少阳合病，必定下利。脉象不负的，为顺。负的，为失，互相克贼，名叫负。脉象滑而数的，是有宿食，应当攻下，适宜用大承气汤。", annotation: "二阳合病热迫下利。脉不负为顺（阳明脉大、少阳脉弦，不相克）。负为相克。脉滑数为宿食，可下。" },
  { id: "SH-257", chapter: "辨阳明病脉证并治", original: "病人无表里证，发热七八日，虽脉浮数者，可下之。假令已下，脉数不解，合热则消谷善饥，至六七日，不大便者，有瘀血，宜抵当汤。", translation: "病人无表里证，发热七八天，虽脉浮数的，可以攻下。假如已经攻下，脉数不解，合热则消谷善饥，到六七天，不大便的，是有瘀血，适宜用抵当汤。", annotation: "发热七八日脉浮数无表里证可下（釜底抽薪）。下后脉数不解消谷善饥不大便为瘀血与热结。抵当汤下瘀血。" },
  { id: "SH-258", chapter: "辨阳明病脉证并治", original: "若脉数不解，而下不止，必协热便脓血也。", translation: "如果脉数不解，而下利不止，必定协热便脓血。", annotation: "下后脉数不解下利不止为热迫大肠，便脓血。" },
  { id: "SH-259", chapter: "辨阳明病脉证并治", original: "伤寒发汗已，身目为黄，所以然者，以寒湿在里不解故也。以为不可下也，于寒湿中求之。", translation: "伤寒发汗后，身目发黄，之所以这样，是因为寒湿在里不解的缘故。不可攻下，在寒湿中寻求治法。", annotation: "寒湿发黄（阴黄）。汗后中阳不足，寒湿郁滞。不可下。当温中散寒除湿。" },
  { id: "SH-260", chapter: "辨阳明病脉证并治", original: "伤寒七八日，身黄如橘子色，小便不利，腹微满者，茵陈蒿汤主之。", translation: "伤寒七八天，身黄如橘子色，小便不利，腹微满的，用茵陈蒿汤主治。", annotation: "此为阳黄（湿热发黄）。黄如橘子色为热重。小便不利腹微满为湿热郁滞。茵陈蒿汤清热利湿退黄。" },
  { id: "SH-261", chapter: "辨阳明病脉证并治", original: "伤寒身黄发热者，栀子柏皮汤主之。", translation: "伤寒身黄发热的，用栀子柏皮汤主治。", annotation: "此为阳黄较轻。但发热身黄无里实。栀子柏皮汤（栀子、甘草、黄柏）清热利湿。" },
  { id: "SH-262", chapter: "辨阳明病脉证并治", original: "伤寒瘀热在里，身必黄，麻黄连轺赤小豆汤主之。", translation: "伤寒瘀热在里，身体必发黄，用麻黄连轺赤小豆汤主治。", annotation: "此为阳黄兼表证。表邪未解瘀热在里发黄。麻黄连轺赤小豆汤解表清热利湿。" },
  { id: "SH-263", chapter: "辨少阳病脉证并治", original: "少阳之为病，口苦，咽干，目眩也。", translation: "少阳病的表现，就是口苦，咽干，目眩。", annotation: "此为少阳病提纲。口苦为胆热上蒸，咽干为热耗津液，目眩为胆热上扰。三症为少阳病基本症状。" },
  { id: "SH-264", chapter: "辨少阳病脉证并治", original: "少阳中风，两耳无所闻，目赤，胸中满而烦者，不可吐下，吐下则悸而惊。", translation: "少阳中风，两耳听不见，目赤，胸中满而烦的，不可吐下，吐下就会心悸而惊。", annotation: "少阳经循行过耳、目、胸。耳无所闻目赤胸中满烦为少阳风火上扰。吐下伤正致悸惊。" },
  { id: "SH-265", chapter: "辨少阳病脉证并治", original: "伤寒，脉弦细，头痛发热者，属少阳。少阳不可发汗，发汗则谵语。此属胃，胃和则愈，胃不和，烦而悸。", translation: "伤寒，脉象弦细，头痛发热的，属少阳。少阳不可发汗，发汗就会说胡话。这是属胃，胃气和就愈，胃气不和，就烦而悸。", annotation: "脉弦细为少阳。头痛发热似太阳但脉不浮而弦细为少阳。误汗伤津致谵语。胃和则愈。" },
  { id: "SH-266", chapter: "辨少阳病脉证并治", original: "本太阳病不解，转入少阳者，胁下硬满，干呕不能食，往来寒热，尚未吐下，脉沉紧者，与小柴胡汤。", translation: "本来太阳病不解，转入少阳的，胁下硬满，干呕不能食，往来寒热，尚未吐下，脉象沉紧的，给予小柴胡汤。", annotation: "太阳转少阳。胁下硬满、干呕不能食、往来寒热为柴胡四大主症。脉沉紧为邪入少阳。小柴胡汤和解。" },
  { id: "SH-267", chapter: "辨少阳病脉证并治", original: "若已吐下、发汗、温针，谵语，柴胡汤证罢，此为坏病。知犯何逆，以法治之。", translation: "如果已经吐下、发汗、温针，说胡话，柴胡汤证罢，这是坏病。知道犯了什么错误，依法救治。", annotation: "误治后柴胡证罢为坏病。辨证论治。" },
  { id: "SH-268", chapter: "辨少阳病脉证并治", original: "三阳合病，脉浮大，上关上，但欲眠睡，目合则汗。", translation: "三阳合病，脉象浮大，上关上，但想睡眠，眼合就出汗。", annotation: "三阳合病。脉浮大上关为热盛。欲眠睡目合则汗为热迫津液。" },
  { id: "SH-269", chapter: "辨少阳病脉证并治", original: "伤寒六七日，无大热，其人躁烦者，此为阳去入阴故也。", translation: "伤寒六七天，无大热，病人躁烦的，这是阳去入阴的缘故。", annotation: "无大热而躁烦为表邪入里。阳去入阴为邪由表入里。" },
  { id: "SH-270", chapter: "辨少阳病脉证并治", original: "伤寒三日，三阳为尽，三阴当受邪，其人反能食而不呕，此为三阴不受邪也。", translation: "伤寒三天，三阳经已尽，三阴当受邪，病人反而能食而不呕，这是三阴不受邪。", annotation: "伤寒传经规律。能食不呕为胃气和，邪不入三阴。" },
  { id: "SH-271", chapter: "辨少阳病脉证并治", original: "伤寒三日，少阳脉小者，欲已也。", translation: "伤寒三天，少阳脉小的，是病将愈。", annotation: "脉小为邪衰。欲已。" },
  { id: "SH-272", chapter: "辨少阳病脉证并治", original: "少阳病欲解时，从寅至辰上。", translation: "少阳病欲解时，从寅时至辰时。", annotation: "寅卯辰为少阳经气旺盛之时。" }
]